const FEATURE_REQUESTS_DATA = [{"id": "db1dce4c-013f-f111-88b5-7c1e52157f10", "featureId": "MFR-M365-38863", "name": "Purview for M365 | Include \"unlabeled\" as a condition in a DLP for Copilot policy", "description": "Add Purview DLP policy configuration when Copilot is selected location to include the action of \"restrict Copilot from processing unlabeled documents.\"", "status": 500350002, "priority": 172430001, "created": "2026-04-23T10:43:45Z", "modified": "2026-04-23T10:44:17Z", "customers": 0, "impactScore": null, "keywords": null, "categoryId": null, "uatId": "664383", "uatUrl": "https://unifiedactiontracker.visualstudio.com/Technical%20Feedback/_workitems/edit/664383", "crmCustomers": []}, {"id": "6bf37050-ed3e-f111-88b5-7ced8d2159c6", "featureId": "MFR-M365-38862", "name": "Larger File Support for Network DLP (128 GB)", "description": "Current file size limit for Network DLP is 4GB with plans to increase to 32 GB. Customers need larger file support. Many ask for 64GB to match what Endpoint DLP supports, others ask for 128 GB to match what Netskope offers.", "status": 172430000, "priority": 172430000, "created": "2026-04-23T08:20:41Z", "modified": "2026-04-23T08:21:47Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["FRED HUTCHINSON CANCER RESEARCH CENTER"]}, {"id": "9c9fe28a-ec3e-f111-88b5-7ced8d2159c6", "featureId": "MFR-M365-38861", "name": "Block with override and policy tip support for Network DLP", "description": "Need ability to block with override and policy tip support for Network DLP policies.", "status": 172430000, "priority": 172430000, "created": "2026-04-23T08:15:09Z", "modified": "2026-04-23T08:48:02Z", "customers": 2, "impactScore": 14, "keywords": null, "categoryId": null, "crmCustomers": ["FRED HUTCHINSON CANCER RESEARCH CENTER", "BANK VONTOBEL AG (Vontobel)"]}, {"id": "6c5dbadc-e83e-f111-88b5-7ced8d2159c6", "featureId": "MFR-M365-38860", "name": "Ability to configure allow list for inline web traffic policies", "description": "When scoping unmanaged apps for inline web traffic policies (Browser/Network DLP) customers want to be able to block all unmanaged apps and configure an allow list rather than explicitly having to define a block list.", "status": 172430000, "priority": 172430000, "created": "2026-04-23T07:48:51Z", "modified": "2026-04-23T08:50:17Z", "customers": 3, "impactScore": 35, "keywords": null, "categoryId": null, "crmCustomers": ["Publix", "Cleveland Clinic (Cleveland Clinic Foundation)", "BANK VONTOBEL AG (Vontobel)"]}, {"id": "102f3fb7-083d-f111-88b5-7c1e52157f8b", "featureId": "MFR-M365-38791", "name": "Admin toggle control for Policy Tips enablement on Mac and Mobile clients", "description": "Provide a clear tenant-level administrative control to enable or disable Microsoft Purview DLP Policy Tips across Outlook clients on macOS, iOS, and Android, including explicit configuration settings governing default enablement behavior during GA rollout.\n\n— Generated by CXE EasyCRM", "status": 172430000, "priority": 172430000, "created": "2026-04-20T22:31:56Z", "modified": "2026-04-20T22:31:56Z", "customers": 0, "impactScore": null, "keywords": null, "categoryId": null, "crmCustomers": []}, {"id": "3ee16cdd-803a-f111-88b5-7c1e5246de6f", "featureId": "MFR-M365-38757", "name": "Purview for A365 | Add agent exposure level (private / shared / enterprise agent) to AI Observability", "description": "Customers \na {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nsee that agent risk materially increases at the point an agent moves from private/self-use to shared usage, and governance needs change again for factory-built/enterprise agents with runtime + pipeline controls. Without a clear “exposure level” indicator in AI Observability, customers can’t quickly contextualize risk or apply the right governance actions", "status": 172430000, "priority": 172430000, "created": "2026-04-17T17:14:25Z", "modified": "2026-04-17T17:14:58Z", "customers": 0, "impactScore": 5, "keywords": null, "categoryId": "0c47924b-9d32-f111-88b5-7c1e5215744c", "crmCustomers": ["SULAVA OY"]}, {"id": "8674b216-6e3a-f111-88b5-7c1e5246de6f", "featureId": "MFR-M365-38756", "name": "Purview for A365 | Improve actionability of Agent risk signals", "description": "a {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nCustomers can identify risky, shadow, or ownerless agents but lack clarity on next steps. Agent risk indicators need tighter mapping to concrete remediation actions (e.g., assign owner, restrict permissions, enforce policies), or governance adoption stalls at discovery.", "status": 172430000, "priority": 172430000, "created": "2026-04-17T15:00:01Z", "modified": "2026-04-17T15:00:40Z", "customers": 0, "impactScore": 5, "keywords": null, "categoryId": "0c47924b-9d32-f111-88b5-7c1e5215744c", "crmCustomers": ["INVOKE"]}, {"id": "6e9a17b2-df38-f111-88b5-6045bdecf97a", "featureId": "MFR-M365-38712", "name": "DLP for Copilot: Restrict Copilot from processing external domain emails completely", "description": "There are legal firms who have signed contracts with their clients and some of them have clauses to not process their data/interactions using AI. They are also in discussion for Copilot rollout however this constraint in the contract is limiting them from proceeding further. They are at risk of client data processing with AI specifically emails. DLP for Copilot restricts emails processing based on sensitivity labels but only applicable on emails later than 1 Jan 2025.DLP for Copilot for external emails in private preview today doesn't cater for external user as recipient.", "status": 172430006, "priority": 172430000, "created": "2026-04-15T15:28:11Z", "modified": "2026-04-21T00:10:24Z", "customers": 2, "impactScore": 60, "keywords": null, "categoryId": null, "crmCustomers": ["CLAYTON UTZ C/O BUDAGE PTY LTD", "長島・大野・常松法律事務所"]}, {"id": "309fea3a-7737-f111-88b4-6045bda73be3", "featureId": "MFR-M365-38661", "name": "DSPM | Display SIT match details in Data Risk Assessment dashboard", "description": "CX-need: Expose Sensitive Information Types (SITs) alongside sensitivity labels in item-level Data Risk Assessment results within the Purview DSPM portal so customers can validate why files are assessed as high risk. Description:Customer has requested than viewing the Item Level assessments in the DPSM Purview portal, that the SITS identified on the files should also be visible along with the label.Customer Scenario:Customer wish to run to assessments against sensitive data but are unable to validate if the files are high risk", "status": 500350000, "priority": 172430000, "created": "2026-04-13T20:27:48Z", "modified": "2026-04-16T07:51:51Z", "customers": 0, "impactScore": null, "keywords": null, "categoryId": "412c9365-0e2e-f111-88b5-7c1e5215744c", "uatId": "727034", "uatUrl": "https://dev.azure.com/unifiedactiontracker/Technical%20Feedback/_workitems/edit/727034", "crmCustomers": []}, {"id": "4a95b0e2-0e34-f111-88b5-7c1e52817b02", "featureId": "MFR-M365-38630", "name": "Purview for A365 | Extended AI Activity Log Retention (30 days → 90–180 days)", "description": "Extended AI Interaction Log Retention (30 days → 90–180 days)", "status": 172430000, "priority": 172430000, "created": "2026-04-09T12:23:22Z", "modified": "2026-04-10T15:44:44Z", "customers": 3, "impactScore": 15, "keywords": null, "categoryId": "0c47924b-9d32-f111-88b5-7c1e5215744c", "crmCustomers": ["LSEG", "MORGAN STANLEY SERVICES GROUP INC. (Morgan Stanley, MORGANSTANLEYANDCO)", "QBE MANAGEMENT SERVICES PTY LTD (QBE Insurance Limited (QBE Insurance Australia))"]}, {"id": "df8afe80-0e34-f111-88b5-7c1e52817b02", "featureId": "MFR-M365-38629", "name": "Purview for A365 | Graph Security API Integration for CommComp → SIEM Export", "description": "Communication Compliance detections should be ingestable into external SIEM systems (e.g., Splunk) via Graph Security API for enterprise-scale monitoring.", "status": 172430000, "priority": 172430000, "created": "2026-04-09T12:20:38Z", "modified": "2026-04-09T12:21:48Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": "0c47924b-9d32-f111-88b5-7c1e5215744c", "crmCustomers": ["LSEG"]}, {"id": "8dc3a875-0b34-f111-88b5-7c1e52817b02", "featureId": "MFR-M365-38628", "name": "Purview for A365 | Friendly Agent Name Resolution in Activity Explorer", "description": "Problem Statement:Activity Explorer should resolve agent GUIDs to human-readable names to improve triage speed and reduce operational friction.https://teams.microsoft.com/l/meeting/details?eventId=AAMkADZmMTBiYTIwLTRmMDMtNDRmMS1iNDk3LWMyZjQ3YWI3NDJlNwBGAAAAAABA56OEpBCRRZ0XZ_EDnlJHBwAXGWKzR8oOSoZ-MdjDd7I-AAAAxthfAABaU2fARRpJSobm_5lgSCd0AAfiH6P0AAA%3d", "status": 172430000, "priority": 172430002, "created": "2026-04-09T11:58:45Z", "modified": "2026-04-17T13:20:55Z", "customers": 1, "impactScore": 10, "keywords": null, "categoryId": "0c47924b-9d32-f111-88b5-7c1e5215744c", "crmCustomers": ["INSIGHT", "LSEG"]}, {"id": "73db0989-2133-f111-88b5-7c1e52817b02", "featureId": "MFR-M365-38608", "name": "Purview for A365 | Test and Red teaming sensitive identification", "description": "DSPM Audit capability does not distinguish between Red Team limit or edge case testing events and “real” Risk based events. Compliance Alerts and Alert process will triggered automatically.[HIGH] Potential Solution: Allow the ability to differentiate between “real” and Red Team testing events or provide a secure audit toggle for Agents/Apps at alert policy level.[Microsoft] Requirement to flag events where agents bypass guardrails or share sensitive information, without capturing actual data.[HIGH]Potential Solution: Configure generic policies to capture such events and integrate with AI gover...", "status": 172430000, "priority": 172430000, "created": "2026-04-08T08:04:23Z", "modified": "2026-04-10T08:46:41Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": "0c47924b-9d32-f111-88b5-7c1e5215744c", "crmCustomers": ["BP (British Petroleum, BP Oil International Ltd, BP Plc)"]}, {"id": "49a4751d-2133-f111-88b5-7c1e52817b02", "featureId": "MFR-M365-38606", "name": "Purview for A365 | Monitoring, Reporting and Data Interpretation – Purview Audit Analytics", "description": "DSPM screens show difficulty in interpreting which environments or agents are relevant for monitoring and audit action due to the proliferation of Agents and Apps and therefore associated volumes of data from many environments and sources.[HIGH]Potential Solution: Add columns or filters in Purview Analytics and Audit screen and reports to distinguish between dev, test, and production environments, and between Solution types such as Foundry / Studio / Fabric Agents and Apps.[Microsoft] DPSM Audit screens display “Risky events” based on Microsoft algorithms and view on what constitutes Risk alon...", "status": 172430000, "priority": 172430000, "created": "2026-04-08T08:01:22Z", "modified": "2026-04-17T13:22:09Z", "customers": 1, "impactScore": 15, "keywords": null, "categoryId": "0c47924b-9d32-f111-88b5-7c1e5215744c", "crmCustomers": ["INSIGHT", "INVOKE", "BP (British Petroleum, BP Oil International Ltd, BP Plc)"]}, {"id": "0bc3b400-1f33-f111-88b5-7c1e52817b02", "featureId": "MFR-M365-38605", "name": "Purview for A365 | Billing and Cost Attribution Challenges for Foundry and Fabric Agents and capability", "description": "Purview pay-as-you-go billing is centralized, providing an OPEX challenge for Digital Workplace who own the platform costs, and making it difficult to recharge costs to individual business units or subscriptions – even retrospectively.Ambiguity in splitting costs for widely used services like Power BI Copilot and Copilot Studio, which are included in E5 licenses and used across the enterprise. [CRITICAL] Potential Solution: Create a Pay-as-you-go solution for all Purview billing at a more granular level. e.g. per Subscription (Foundry/Copilot Studio) and Workspace (Fabric) [Microsoft] Potentia...", "status": 172430000, "priority": 172430000, "created": "2026-04-08T07:46:13Z", "modified": "2026-04-09T12:01:48Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": "0c47924b-9d32-f111-88b5-7c1e5215744c", "crmCustomers": ["BP (British Petroleum, BP Oil International Ltd, BP Plc)"]}, {"id": "ca2e0740-1e33-f111-88b5-7c1e52817b02", "featureId": "MFR-M365-38604", "name": "Purview for A365 | Granular monitoring and Policy controls for A365", "description": "Difficulty in distinguishing between dev, test, and production environments for Copilot Studio agents; all environments are monitored tenant-wide, making it hard to filter relevant data.How it applies to purview is they  Lack of ability to apply DLP and other policies at a more granular level (e.g., specific agents/apps rather than blanket policies across all agents).", "status": 172430000, "priority": 172430000, "created": "2026-04-08T07:40:48Z", "modified": "2026-04-09T12:02:08Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": "0c47924b-9d32-f111-88b5-7c1e5215744c", "crmCustomers": ["BP (British Petroleum, BP Oil International Ltd, BP Plc)"]}, {"id": "7db50235-8031-f111-88b5-7ced8d2159c6", "featureId": "MFR-M365-38542", "name": "Ability to enforce website/domain-level filtering controls on sources used by M365 Copilot web search when generating responses", "description": "When an M365 Copilot–licensed or non-licensed user submits a prompt, Copilot web search aggregates content from multiple external websites to construct a response. While Copilot currently provides visibility into the websites/domains used, customers do not have the ability to control or restrict which websites/domains are allowed to contribute to the generated response.", "status": 172430000, "priority": 172430000, "created": "2026-04-06T06:17:00Z", "modified": "2026-04-06T06:17:51Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["STANDARD CHARTERED BANK"]}, {"id": "bae5e1f5-802f-f111-88b5-7c1e5248e93b", "featureId": "MFR-M365-38536", "name": "DSPM AI Observability | Map Agent risk to corresponding AI interactions in DSPM", "description": "Summary - Data Security Investigations flow relating to agents' risk has low usability where an identified risk (for example – oversharing) is not directly mapped into corresponding AI Interactions. 'Viewing all activities' shows hundreds of activities with no mapping to ones related to the risk (such as oversharing).Repro: In DSPM observability it shows risk per agent, like here 7 oversharing that contributed to high risk Now customers want to see the \"7\" oversharing instances.. they cant click on the 7 to drill down but they can click on \"view all activities\". This gives them hundreds of AI ...", "status": 172430000, "priority": 172430000, "created": "2026-04-03T17:17:22Z", "modified": "2026-04-06T17:13:57Z", "customers": 3, "impactScore": 15, "keywords": null, "categoryId": null, "crmCustomers": ["Ernst & Young (EY, E&Y, EY GLOBAL SERVICES LIMITED )", "London Stock Exchange Group", "DRILLING INFO"]}, {"id": "d274367f-cf2d-f111-88b5-7ced8d17ff64", "featureId": "MFR-M365-38456", "name": "Provide visibility and prevention controls for OpenClaw using Purview DSPM", "description": "Provide visibility and prevention controls for OpenClaw using Purview DSPM. https://openclaw.ai/", "status": 172430000, "priority": 172430000, "created": "2026-04-01T13:34:33Z", "modified": "2026-04-01T13:34:33Z", "customers": 0, "impactScore": null, "keywords": null, "categoryId": null, "crmCustomers": []}, {"id": "db3cd620-3b2b-f111-88b5-7ced8d17ff64", "featureId": "MFR-M365-38399", "name": "DLP: OCR usage and billing report", "description": "Customer facing dashboard that give them insights on Report should reflect which files/images are being scanned by OCR, how many files/images are scanned, what file/image types are scanned vs skipped, and the volume of OCR activity contributing to billing.Reports should support filter by workloads, file type, file size, date/time.", "status": 172430000, "priority": 172430000, "created": "2026-03-29T06:47:19Z", "modified": "2026-04-10T15:30:41Z", "customers": 2, "impactScore": 35, "keywords": "OCR", "categoryId": null, "uatId": "697453", "uatUrl": "https://dev.azure.com/unifiedactiontracker/Technical%20Feedback/_workitems/edit/697453", "crmCustomers": ["FIDELITY INVESTMENTS (FIDELITY TECHNOLOGY GROUP LLC, located in USA)", "US Bank"]}, {"id": "b772d67f-e029-f111-88b5-7c1e521995b5", "featureId": "MFR-M365-38375", "name": "M365 | Web Grounding DLP: Support for Customized end user notifications", "description": "Customers would like to be able to customize end user notifications in web grounding DLP as they are not sure if end users would understand what this means. They would also like hyperlink support to link to an internal article.", "status": 172430000, "priority": 172430000, "created": "2026-03-27T13:26:03Z", "modified": "2026-04-23T10:59:58Z", "customers": 3, "impactScore": 45, "keywords": null, "categoryId": null, "crmCustomers": ["BNP Paribas (BNPP)", "MICROSOFT CORPORATION", "Cleveland Clinic (Cleveland Clinic Foundation)"]}, {"id": "1d187f88-0329-f111-88b4-7ced8d2159c6", "featureId": "MFR-M365-38343", "name": "GCCH Support for 1P Network Data Security", "description": "Enable Microsoft Purview Inline DLP (Network DLP) capability in GCCH to achieve parity with Worldwide (WW) cloud and support customers requiring complete DLP coverage.", "status": 172430000, "priority": 172430000, "created": "2026-03-26T11:04:25Z", "modified": "2026-03-26T11:05:22Z", "customers": 0, "impactScore": null, "keywords": null, "categoryId": null, "uatId": "721144", "uatUrl": "https://dev.azure.com/unifiedactiontracker/Technical%20Feedback/_workitems/edit/721144", "crmCustomers": []}, {"id": "88b06c5f-fb26-f111-88b5-6045bdd45021", "featureId": "MFR-M365-38280", "name": "Data risk assessment | Remediation action to move highly sensitive content to a more restricted site", "description": "As a remediation action from data risk assessment, want the ability to move highly sensitive content that's been detected as overshared on an unrestricted site to a more restricted site", "status": 172430000, "priority": 172430000, "created": "2026-03-23T21:00:58Z", "modified": "2026-03-23T21:01:33Z", "customers": 0, "impactScore": 3, "keywords": null, "categoryId": null, "crmCustomers": ["ACCENTURE/AVANADE"]}, {"id": "407ee5e0-fa26-f111-88b5-6045bdd45021", "featureId": "MFR-M365-38279", "name": "Data risk assessment | Scan specifically for sites that are accessed by Copilot or by agents", "description": "Data risk assessment to run a scan specifically for sites and content that Copilot and agents have accessed, including what types of agents are accessing which types of sites (e.g. finance sites accessed only by finance agents)", "status": 172430000, "priority": 172430000, "created": "2026-03-23T20:57:19Z", "modified": "2026-03-23T20:57:53Z", "customers": 0, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["ACCENTURE/AVANADE"]}, {"id": "0a817734-c326-f111-88b4-7c1e5246de6f", "featureId": "MFR-M365-38276", "name": "Capability to run custom data risk assessment scan based on site level labels", "description": "Capability to run custom data risk assessment scan based on site level labels", "status": 172430000, "priority": 172430000, "created": "2026-03-23T14:18:56Z", "modified": "2026-04-01T21:14:19Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": "412c9365-0e2e-f111-88b5-7c1e5215744c", "crmCustomers": ["Nestle (Nestlé S.A.)"]}, {"id": "56891421-c326-f111-88b4-7c1e5246de6f", "featureId": "MFR-M365-38275", "name": "Capability to run custom data risk assessment scan based on communication sites and collaboration(teams) sites", "description": "Capability to run custom data risk assessment scan based on communication sites and collaboration(teams) sites", "status": 172430000, "priority": 172430000, "created": "2026-03-23T14:18:16Z", "modified": "2026-03-23T14:18:36Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["Nestle (Nestlé S.A.)"]}, {"id": "1aefeb00-c326-f111-88b4-7c1e5246de6f", "featureId": "MFR-M365-38274", "name": "Capability to run custom data risk assessment scan based on Sensitive content (SITs) along with Confidence levels and instance count", "description": "Capability to run custom data risk assessment scan based on Sensitive content (SITs) along with Confidence levels and instance count", "status": 172430000, "priority": 172430000, "created": "2026-03-23T14:17:29Z", "modified": "2026-03-23T14:17:54Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["Nestle (Nestlé S.A.)"]}, {"id": "1bc404ec-c226-f111-88b4-7c1e5246de6f", "featureId": "MFR-M365-38273", "name": "Capability to run custom data risk assessment scan based on labels", "description": "Capability to run custom data risk assessment scan based on labels", "status": 172430000, "priority": 172430000, "created": "2026-03-23T14:16:46Z", "modified": "2026-03-23T14:17:06Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["Nestle (Nestlé S.A.)"]}, {"id": "b01b4ac8-c226-f111-88b4-7c1e5246de6f", "featureId": "MFR-M365-38272", "name": "Capability to run custom data risk assessment scan based on Sensitive content (SITs)", "description": "Capability to run custom data risk assessment scan based on Sensitive content (SITs)", "status": 172430000, "priority": 172430000, "created": "2026-03-23T14:15:54Z", "modified": "2026-03-23T14:16:28Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["Nestle (Nestlé S.A.)"]}, {"id": "8ba03ac5-c126-f111-88b4-7c1e5246de6f", "featureId": "MFR-M365-38271", "name": "Capability to remediate stale or inactive sharing links within data risk assessments", "description": "Capability to remediate stale or inactive sharing links within data risk assessments. Including also unused sharing links (never redeemed or only accessed by the creator). Additionally, the ability to set expiration dates on existing sharing links (e.g. auto expire after 30 days", "status": 172430000, "priority": 172430000, "created": "2026-03-23T14:08:31Z", "modified": "2026-03-23T21:02:06Z", "customers": 1, "impactScore": 8, "keywords": null, "categoryId": null, "crmCustomers": ["Ravanty Tech Consulting", "Nestle (Nestlé S.A.)"]}, {"id": "0c87bebc-c026-f111-88b4-7c1e5246de6f", "featureId": "MFR-M365-38270", "name": "Capability to roll back item-level remediation actions performed as part of data risk assessments", "description": "Capability to roll back item-level remediation actions performed as part of data risk assessments", "status": 172430000, "priority": 172430000, "created": "2026-03-23T14:01:07Z", "modified": "2026-03-23T14:01:51Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["Nestle (Nestlé S.A.)"]}, {"id": "b8e89092-bf26-f111-88b4-7c1e5246de6f", "featureId": "MFR-M365-38268", "name": "Minimize the application permissions required to perform item-level remediation", "description": "Minimize the application permissions required to perform item-level remediation", "status": 172430000, "priority": 172430000, "created": "2026-03-23T13:52:48Z", "modified": "2026-04-21T11:18:08Z", "customers": 1, "impactScore": 10, "keywords": null, "categoryId": null, "crmCustomers": ["Nestle (Nestlé S.A.)"]}, {"id": "3e1ab0cb-7e24-f111-8343-7c1e52157f83", "featureId": "MFR-M365-38241", "name": "Extending Edge Discover/Protect behaviors to Mobile", "description": "Extending Edge Discover/Protect behaviors to Mobile", "status": 172430000, "priority": 172430000, "created": "2026-03-20T17:04:11Z", "modified": "2026-03-20T17:05:18Z", "customers": 1, "impactScore": 3, "keywords": null, "categoryId": null, "crmCustomers": ["Nestle (Nestlé S.A.)"]}, {"id": "4bb54961-7e24-f111-8343-7c1e52157f83", "featureId": "MFR-M365-38240", "name": "Inline browser/network new condition: Number of characters (greater or less than)", "description": "- Number of characters and text in scope of the AI – 125 chars or more, 200 chars, could be a way to exfilt... Right balance of “scan big” versus “scan small” like multi-prompt scenarios. How it’s being used versus the block mechanisms. ...Project pineapple, char count of 100 chars = match for the smaller", "status": 172430000, "priority": 172430000, "created": "2026-03-20T17:01:12Z", "modified": "2026-03-20T17:01:52Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["Nestle (Nestlé S.A.)"]}, {"id": "aa861bdf-7d24-f111-8343-7c1e52157f83", "featureId": "MFR-M365-38239", "name": "Reduce friction across multiple Admin roles required  for inline browser policies", "description": "Reduce friction across multiple Admin roles required  for inline browser policies", "status": 172430000, "priority": 172430000, "created": "2026-03-20T16:57:34Z", "modified": "2026-03-20T16:58:47Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["Nestle (Nestlé S.A.)"]}, {"id": "0944086b-6824-f111-8343-7c1e52157f83", "featureId": "MFR-M365-38238", "name": "Block with override (include justification entry) for Edge for business DLP", "description": "Block with override (include justification entry) for Edge for business DLP", "status": 172430000, "priority": 172430000, "created": "2026-03-20T14:24:02Z", "modified": "2026-03-20T16:51:35Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["Nestle (Nestlé S.A.)"]}, {"id": "ab920755-6724-f111-8343-7c1e52157f83", "featureId": "MFR-M365-38237", "name": "Allow admins to customize the message to the end user in Edge for block policies (unmanaged and managed apps, inline browser scenarios)", "description": "Allow admins to customize the message to the end user in Edge for block policies (unmanaged and managed apps, inline browser scenarios)", "status": 172430000, "priority": 172430000, "created": "2026-03-20T14:16:07Z", "modified": "2026-03-20T14:18:12Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["Nestle (Nestlé S.A.)"]}, {"id": "0ed716d0-f21e-f111-8342-7c1e5215744c", "featureId": "MFR-M365-37618", "name": "Ability to view prompt and response in a single AI Interaction for Enterprise AI apps", "description": "Ability to view prompt and response in a single AI Interaction in Activity Explorer,", "status": 172430000, "priority": 172430000, "created": "2026-03-13T15:39:30Z", "modified": "2026-03-13T16:03:06Z", "customers": 3, "impactScore": 35, "keywords": null, "categoryId": null, "crmCustomers": ["Corning Inc.", "BP (British Petroleum, BP Oil International Ltd, BP Plc)", "Cleveland Clinic (Cleveland Clinic Foundation)"]}, {"id": "487e9a78-f21e-f111-8342-7c1e5215744c", "featureId": "MFR-M365-37617", "name": "Grounding Data Visibility in DSPM for AI for Copilot in Fabric", "description": "ability to view the Grounding Data (“Data Resources Accessed”) in DSPM for AI Activity Explorer AI Interactions", "status": 172430000, "priority": 172430000, "created": "2026-03-13T15:37:04Z", "modified": "2026-03-13T16:01:02Z", "customers": 2, "impactScore": 10, "keywords": null, "categoryId": null, "crmCustomers": ["Accenture", "DEERE & CO (DEERE COMPANY, John Deere)"]}, {"id": "2f5c1b10-f21e-f111-8342-7c1e5215744c", "featureId": "MFR-M365-37616", "name": "Grounding Data Visibility in DSPM for AI for Foundry & Enterprise AI Apps", "description": "ability to view the Grounding Data (“Data Resources Accessed”) in DSPM for AI Activity explorer", "status": 172430000, "priority": 172430000, "created": "2026-03-13T15:34:11Z", "modified": "2026-03-13T16:10:45Z", "customers": 3, "impactScore": 15, "keywords": null, "categoryId": null, "crmCustomers": ["BP (British Petroleum, BP Oil International Ltd, BP Plc)", "Corning Inc.", "Barclays Bank plc"]}, {"id": "9be2a9f7-741e-f111-8342-7c1e521995b5", "featureId": "MFR-M365-37609", "name": "M365 | Remove workaround options in Copilot response when user does not have extract rights", "description": "When a user tries to summarize a file in Copilot and they don't have the correct permissions, like extract rights, then it tells the user how to get around it. Like copy and pasting the contents of the file into copilot instead. Customers would like to be able to remove this part of Copilot's response.", "status": 172430000, "priority": 172430000, "created": "2026-03-13T00:38:35Z", "modified": "2026-03-26T15:19:48Z", "customers": 1, "impactScore": 3, "keywords": null, "categoryId": null, "crmCustomers": ["Cisco Systems"]}, {"id": "f6f5fe0f-dc1d-f111-8342-6045bdecfc3f", "featureId": "MFR-M365-37594", "name": "DSPM AI Observability | Add meaningful agent context in AI observability", "description": "The agent name alone is insufficient at scale. Two agents with similar names can have radically different risk profiles. The same agent name can mean different things across teams, tenants, or business units. Without standardized agent descriptions/use cases, risk signals become harder to interpret and triage across tens of thousands of agents, undermining policy decisions and trust in the platform.Introduce a minimal “agent registration” expectation (use case, data sources, risk profile) and align it to workflows like monitoring, attestation, and recommendations so governance is actionable - ...", "status": 500350008, "priority": 172430000, "created": "2026-03-12T06:24:04Z", "modified": "2026-04-08T22:54:35Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["KPMG"]}, {"id": "d96afae3-1718-f111-8342-6045bdd45021", "featureId": "MFR-M365-37435", "name": "M365 | DLP for Copilot to surface sensitivity label meta data in DLP rule match", "description": "a {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nFor DLP for Copilot, when a DLP rule matches based on a sensitivity label, the label itself is not surfaced as a parameter in Activity Explorer for the resulting DLP event.This is inconsistent with:Other DLP workloads, where label metadata is visibleSIT‑based DLP for Copilot, where matched SIT details are surfaced Customers want to surface sensitivity label metadata (e.g., label name/ID) in Activity Explorer for DLP for Copilot events when the rule match...", "status": 172430000, "priority": 172430000, "created": "2026-03-04T22:17:19Z", "modified": "2026-03-26T14:11:23Z", "customers": 0, "impactScore": 3, "keywords": "DLP for Copilot", "categoryId": null, "crmCustomers": ["THREATSCAPE LIMITED HQ"]}, {"id": "05337f35-eb17-f111-8341-7ced8d2159c6", "featureId": "MFR-M365-37428", "name": "Purview for A365 | DSPM AI Observability ('Within AI risk' switch from \"No Data Available\" to \"No Risk Detected\")", "description": "Description: Customers would like to see “No risk detected” vs. “No Data Available” in the “Within AI risk” section of the AI Observability page. \"No Data Available\" - \"makes me think that there is something broken. That there are issues with my pipeline.\" - DOW", "status": 172430003, "priority": 172430000, "created": "2026-03-04T16:57:21Z", "modified": "2026-03-30T17:14:46Z", "customers": 1, "impactScore": 3, "keywords": null, "categoryId": null, "crmCustomers": ["THE DOW CHEMICAL COMPANY"]}, {"id": "47d7c00a-da17-f111-8342-7c1e52021284", "featureId": "MFR-M365-37426", "name": "M365 | Default label Copilot generated content", "description": "a {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nAI‑generated content is enterprise data the moment it is created. If Copilot outputs are written to OneDrive or SharePoint without mandatory sensitivity labels and visible classification markers, unclassified data can persist until downstream controls act—creating regulatory and governance gaps. Relying on post‑creation enforcement is insufficient in regulated environments where classification is required at the point of creation. Mandatory pre‑write lab...", "status": 172430000, "priority": 172430000, "created": "2026-03-04T14:54:28Z", "modified": "2026-03-26T15:19:24Z", "customers": 1, "impactScore": 30, "keywords": null, "categoryId": null, "crmCustomers": ["HSBC (HONGKONG & SHANGHAI BANKING CORP. LTD.)"]}, {"id": "a4713c34-ea13-f111-8342-7c1e52817aa2", "featureId": "MFR-M365-37376", "name": "Automate Purview toggle enablement in Foundry for Azure subscriptions via Azure policy or by an administrative method", "description": "Automate Purview toggle enablement in Foundry for Azure subscriptions via Azure policy or by an administrative method", "status": 172430000, "priority": 172430000, "created": "2026-02-27T14:40:05Z", "modified": "2026-02-27T14:44:02Z", "customers": 3, "impactScore": 15, "keywords": null, "categoryId": null, "crmCustomers": ["LENOVO", "Volvo Group", "Asurion, LLC"]}, {"id": "d49d0623-3513-f111-8342-7c1e52817aa2", "featureId": "MFR-M365-37365", "name": "M365 | DLP for Copilot to support condition 'Document property is / contains' condition", "description": "law firm clients that store customer identifiers (e.g. Client ID, Matter ID, Case Number) exclusively in document metadata. This is a common and intentional practice in the legal sector to tag documents with customer-specific identifiers that do not appear in the file body and therefore are not detectable by standard SITs. The ask is to extend DLP for Copilot with a ‘Document property is / contains’ condition, allowing admins to block Copilot from processing prompts when referenced files include specific metadata values. This is required for legal-sector rollouts, where document sensitivity is...", "status": 172430000, "priority": 172430000, "created": "2026-02-26T17:04:01Z", "modified": "2026-03-26T14:11:39Z", "customers": 3, "impactScore": 55, "keywords": "DLP for Copilot", "categoryId": null, "crmCustomers": ["THREATSCAPE LIMITED HQ", "MATHESON COM", "MERCURY ENGINEERING", "SHANNON ENGINE SUPPORT"]}, {"id": "b775d3af-db12-f111-8342-6045bdecf51b", "featureId": "MFR-M365-37362", "name": "M365 | Upload file to Copilot - bypass security policy (ex Edlp)", "description": "When a user upload a file in copilot, this create a copy of the file in a folder in onedrive. This process bypass blockers customer can have to avoid for user to being able to upload specific file in onedrive (ex Edlp policy > content cointeins sensitivity labels >block upload to ondrive)\na {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nWhen a user uploads a file to Microsoft 365 Copilot, a copy of the file is created in OneDrive as part of the Copilot processing flow. This upload path isn’t governed b...", "status": 172430000, "priority": 172430000, "created": "2026-02-26T06:23:39Z", "modified": "2026-03-26T15:11:57Z", "customers": 3, "impactScore": 33, "keywords": null, "categoryId": null, "crmCustomers": ["UniCredit Banka d.d. BiH (UniCredit Bank a.d. Banja Luka, UNICREDITO ITALIANO SP, Uni Credit Bank, MS Sales Id 1291348A)", "KPMG", "STC SOLUTIONS"]}, {"id": "31ab6208-e710-f111-8342-7c1e52817b02", "featureId": "MFR-M365-37295", "name": "P4AI | Data risk assessment | Distinguish label-eligible vs non-eligible file types in risk assessment", "description": "a {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nCertain file types do not support sensitivity labeling or classification at rest. Including these files inflates unlabeled counts and creates a false perception of widespread oversharing or governance failure.\na {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nUpdate the data risk assessment experience to distinguish label‑eligible file types from non‑label‑eligibl...", "status": 500350000, "priority": 172430000, "created": "2026-02-23T18:39:54Z", "modified": "2026-03-24T19:01:03Z", "customers": 1, "impactScore": 15, "keywords": "Data Risk Assessment", "categoryId": null, "crmCustomers": ["PROTIVITI (Robert Half)", "Corning Inc."]}, {"id": "8aa565ca-e610-f111-8342-7c1e52817b02", "featureId": "MFR-M365-37294", "name": "P4AI | Data risk assessment | Preserve 'last modified' metadata during automated labeling", "description": "a {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nProvide an option to preserve or update the “last modified” timestamp when a sensitivity label is applied as part of an automated remediation or auto‑labeling workflow. \na {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nAutomatically updating the “last modified” field can unintentionally impact downstream controls such as retention, disposition, and audit policies...", "status": 500350000, "priority": 172430000, "created": "2026-02-23T18:38:10Z", "modified": "2026-03-18T18:22:56Z", "customers": 0, "impactScore": 3, "keywords": "Data Risk Assessment", "categoryId": null, "crmCustomers": ["THREATSCAPE LIMITED HQ"]}, {"id": "dd78d161-e610-f111-8342-7c1e52817b02", "featureId": "MFR-M365-37293", "name": "M365 | DLP for Copilot controls for cross-tenant content exposure", "description": "a {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nCustomers are concerned that if a guest user has access to external-tenant content, Copilot can still reason over it, creating unintended data exposure across trust boundaries. \na {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nProvide stronger DLP controls to limit Copilot reasoning over content that originates in another tenant, even when access is granted via c...", "status": 172430000, "priority": 172430000, "created": "2026-02-23T18:35:17Z", "modified": "2026-04-15T15:11:55Z", "customers": 0, "impactScore": 3, "keywords": null, "categoryId": null, "crmCustomers": ["PROTIVITI (Robert Half)"]}, {"id": "a8b651e1-e510-f111-8342-7c1e52817b02", "featureId": "MFR-M365-37291", "name": "M365 | DLP for Copilot to support condition 'document could not be scanned'", "description": "a {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nUnscannable or failed-scan content is often treated by customers as implicitly high risk, yet today cannot be reliably gated in Copilot workflows.", "status": 172430000, "priority": 172430000, "created": "2026-02-23T18:31:43Z", "modified": "2026-03-26T14:12:08Z", "customers": 0, "impactScore": 3, "keywords": null, "categoryId": null, "crmCustomers": ["THREATSCAPE LIMITED HQ"]}, {"id": "26df1aad-e510-f111-8342-7c1e52817b02", "featureId": "MFR-M365-37290", "name": "M365 | DLP for Copilot to support condition 'content is not labeled'", "description": "a {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nMany customers are early in their labeling journey and want to prevent Copilot access to unlabeled content by default. Today, the lack of an explicit “not labeled” condition limits their ability to enforce governance-first adoption of Copilot.", "status": 172430000, "priority": 172430000, "created": "2026-02-23T18:30:09Z", "modified": "2026-04-07T09:16:46Z", "customers": 6, "impactScore": 114, "keywords": "DLP for Copilot", "categoryId": null, "uatId": "724670", "uatUrl": "https://dev.azure.com/unifiedactiontracker/Technical%20Feedback/_queries/edit/724670/?queryId=fe2a745c-3561-4e98-99ba-222b358e5971", "crmCustomers": ["BANQUE CANTONALE DU VALAIS", "BNP Paribas (BNPP)", "ADMIRAL INSURANCE SERVICES LTD (EUI LTD)", "HULL COLLEGE", "PM GROUP", "PENSPEN", "THREATSCAPE LIMITED HQ"]}, {"id": "90617b75-e510-f111-8342-7c1e52817b02", "featureId": "MFR-M365-37289", "name": "M365 | DLP for Copilot to support condition 'file extension / file type is'", "description": "a {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nCustomers frequently work with file formats (notably AutoCAD) that cannot be reliably scanned or labeled. Customers want to explicitly block Copilot from processing these high-risk formats.", "status": 172430000, "priority": 172430000, "created": "2026-02-23T18:28:34Z", "modified": "2026-03-26T15:12:23Z", "customers": 0, "impactScore": 3, "keywords": "DLP for Copilot", "categoryId": null, "crmCustomers": ["THREATSCAPE LIMITED HQ"]}, {"id": "95eb8aef-610e-f111-8407-7ced8d17ff64", "featureId": "MFR-M365-37256", "name": "Prevent viewing of PowerBI reports from unmanaged devices based on sensitivity label of the report", "description": "Prevent viewing of PowerBI reports from unmanaged devices based on sensitivity label of the report.  Customer also wants to prevent download of PowerBI reports on unmanaged devices based on label of report which is supported today via Purview managed apps DLP policies.  Originally requested by customers using MDA session policies.", "status": 172430000, "priority": 172430000, "created": "2026-02-20T13:42:05Z", "modified": "2026-02-20T13:45:22Z", "customers": 3, "impactScore": 23, "keywords": null, "categoryId": null, "crmCustomers": ["Cleveland Clinic (Cleveland Clinic Foundation)", "The Emirates Group", "Corteva (AGCompany, from DuPont)"]}, {"id": "ae7c9aa6-500e-f111-8407-7ced8d17ff64", "featureId": "MFR-M365-37255", "name": "Managed Apps Policies for B2B Users in Teams", "description": "Support managed apps DLP policies for B2B users in Teams.  Current known limitation for MDA session policies: https://learn.microsoft.com/en-us/defender-cloud-apps/caac-known-issues#external-b2b-users-in-teams", "status": 172430000, "priority": 172430000, "created": "2026-02-20T11:38:19Z", "modified": "2026-02-20T11:39:11Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["MYDELTEKGCC"]}, {"id": "1d93a636-4e0e-f111-8407-7ced8d17ff64", "featureId": "MFR-M365-37254", "name": "Ability to scope Purview Managed App policies to Sharepoint Site Collections", "description": "Today Purview managed apps DLP policies allow you to scope the policy to different managed apps including Sharepoint Online, but customers need ability to scope the policy to only certain Sharepoint Online Site Collections.  Request from multiple customers migrating from MDA session policies (this capability was requested for MDA session policies).", "status": 172430000, "priority": 172430000, "created": "2026-02-20T11:20:52Z", "modified": "2026-02-20T11:23:39Z", "customers": 2, "impactScore": 6, "keywords": null, "categoryId": null, "crmCustomers": ["Wipro Limited", "Providence Health (Sisters of Providence Health Systems)"]}, {"id": "31afa76f-400e-f111-8406-7ced8d2159c6", "featureId": "MFR-M365-37253", "name": "Ability to identify ChatGPT Enterprise, Consumer, and unauthenticated users and apply Edge for Business DLP policies accordingly", "description": "Ability to identify ChatGPT Enterprise, Consumer, and unauthenticated users and apply Edge for Business DLP policies accordingly", "status": 172430000, "priority": 172430000, "created": "2026-02-20T09:42:14Z", "modified": "2026-02-20T09:57:09Z", "customers": 3, "impactScore": 15, "keywords": null, "categoryId": null, "crmCustomers": ["G42", "ADIA (ABU DHABI INVESTMENT AUTHORITY)", "Swiss Reinsurance Company LTD (SwissRE)"]}, {"id": "62450837-3a0e-f111-8406-7ced8d2159c6", "featureId": "MFR-M365-37252", "name": "Support to enforce DLP policies on selected AI applications and agents within Microsoft Foundry", "description": "Support to enforce DLP policies on selected AI applications and agents within Microsoft Foundry", "status": 172430000, "priority": 172430000, "created": "2026-02-20T08:57:52Z", "modified": "2026-03-13T16:09:01Z", "customers": 4, "impactScore": 20, "keywords": null, "categoryId": null, "crmCustomers": ["BP (British Petroleum, BP Oil International Ltd, BP Plc)", "DEERE & CO (DEERE COMPANY, John Deere)", "Asurion, LLC", "Volvo Group"]}, {"id": "0619ab7e-390e-f111-8406-7ced8d2159c6", "featureId": "MFR-M365-37251", "name": "Support for private endpoints when enabling the Purview toggle in Microsoft Foundry", "description": "Support for private endpoints when enabling the Purview toggle in Microsoft Foundry", "status": 172430000, "priority": 172430000, "created": "2026-02-20T08:52:33Z", "modified": "2026-02-20T09:04:29Z", "customers": 5, "impactScore": 25, "keywords": null, "categoryId": null, "crmCustomers": ["Volvo Group", "BP (British Petroleum, BP Oil International Ltd, BP Plc)", "Novartis AG", "PNC", "Allstate Insurance"]}, {"id": "d3bca857-070d-f111-8407-7ced8d17ff64", "featureId": "MFR-M365-37228", "name": "M365 | Add an Audit‑only mode for Copilot DLP policies that detects Sensitive Information Types (SITs) in user prompts and triggers alerts without blocking Copilot processing", "description": "a {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nFeature request: Add an Audit‑only mode for Copilot DLP policies that detects Sensitive Information Types (SITs) in user prompts and triggers alerts without blocking Copilot processing.Impact: Today Copilot DLP acts as a hard block when SITs are detected, which limits visibility and drives users to bypass controls. An audit‑only option would enable organizations to monitor and understand real prompt risk, collect signals for tuning policies, and reduce u...", "status": 172430000, "priority": 172430000, "created": "2026-02-18T20:21:02Z", "modified": "2026-03-26T15:12:53Z", "customers": 1, "impactScore": 15, "keywords": null, "categoryId": null, "crmCustomers": ["TOWERS WATSON DELAWARE INC. (Willis Towers Watson)"]}, {"id": "83ccc917-3d0b-f111-8406-7ced8d17f4cc", "featureId": "MFR-M365-37187", "name": "Copilot in Dynamics 365 Sales AI interaction visibility in Purview DSPM.", "description": "Copilot in Dynamics 365 Sales AI interaction visibility in Purview DSPM.To initiate the Copilot in Dynamics 365 Sales AI interaction, One of the use cases is a business user goes to https://make.powerapps.com --> Apps--> Shared with me-->  One of the app e.g. (Sales hub)--> launches the app--> Connect  to Copilot in Dynamics 365 Sales. (additional information: Steps to enable Copilot in Dynamics 365 Sales: Turn on and set up Copilot in Dynamics 365 Sales | Microsoft Learn)", "status": 172430000, "priority": 172430000, "created": "2026-02-16T13:40:46Z", "modified": "2026-02-16T13:42:03Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["STANDARD CHARTERED BANK"]}, {"id": "56bd4193-cc05-f111-8406-6045bdecf97a", "featureId": "MFR-M365-37096", "name": "Google AI mode's interaction protection via Edge for Business /Browser", "description": "Google AI mode's interaction protection via Edge for Business /Browser", "status": 172430000, "priority": 172430000, "created": "2026-02-09T15:32:48Z", "modified": "2026-04-23T08:10:08Z", "customers": 3, "impactScore": 15, "keywords": null, "categoryId": null, "crmCustomers": ["STANDARD CHARTERED BANK", "Publix"]}, {"id": "8daa112e-9502-f111-8407-7c1e52817aa2", "featureId": "MFR-M365-37068", "name": "In-line Response DLP for Foundry AI application", "description": "In-line Response DLP for Foundry AI application", "status": 172430000, "priority": 172430000, "created": "2026-02-05T13:18:38Z", "modified": "2026-02-05T13:20:49Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["MUFG BANK  LTD"]}, {"id": "6f34be3c-fc01-f111-8406-7ced8d1ca6c3", "featureId": "MFR-M365-37056", "name": "P4AI | Native Integration to Push Purview Agent Activity Signals into Microsoft Sentinel", "description": "a {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nPurview AI Agent activity signals (e.g., agent interactions, actions taken, risk events, anomalies, model usage) to flow natively and automatically into Microsoft Sentinel without requiring custom pipelines or manual exports.", "status": 500350000, "priority": 172430000, "created": "2026-02-04T19:03:50Z", "modified": "2026-04-14T17:47:15Z", "customers": 0, "impactScore": null, "keywords": null, "categoryId": null, "crmCustomers": []}, {"id": "48c8dd88-fb01-f111-8406-7ced8d1ca6c3", "featureId": "MFR-M365-37055", "name": "M365 | Prevent Copilot from processing text copied from labelled files", "description": "Customers are asking for a more granular control that stops Copilot from processing a prompt when the user pastes text originating from a sensitivity‑labelled file—without fully blocking copy/extract operations at the OS level. \na {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nToday, the only native mechanism to prevent labelled content from being copied into an AI prompt is to use the Azure Rights Management “Copy (Extract)” permission within a label but this is highly restrictive and blocks all forms...", "status": 172430000, "priority": 172430000, "created": "2026-02-04T18:58:48Z", "modified": "2026-03-26T15:13:19Z", "customers": 0, "impactScore": 6, "keywords": null, "categoryId": null, "crmCustomers": ["DEFEND LIMITED", "NEDSCAPER"]}, {"id": "d7cb07f4-fa01-f111-8406-7ced8d1ca6c3", "featureId": "MFR-M365-37053", "name": "M365 | Block processing of external emails to prevent XPIA (prompt injection) attacks", "description": "As part of the new feature we are developing to block processing of external emails to prevent XPIA prompt injection attacks, partners have requested that they can configure an 'Allow\" or exclusions from the policy for domain trusted partners.", "status": 172430005, "priority": 172430000, "created": "2026-02-04T18:54:47Z", "modified": "2026-03-26T15:13:54Z", "customers": 0, "impactScore": null, "keywords": null, "categoryId": null, "crmCustomers": []}, {"id": "86148322-3601-f111-8407-7c1e52157f10", "featureId": "MFR-M365-37032", "name": "DSPM | Data risk assessments for Azure files", "description": "a {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nEnable Data Risk Assessments for Azure Files within Microsoft Purview DSPM to provide full visibility into sensitive data exposure, oversharing, and labeling quality across Azure Files repositories. \na {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nPartners report that many enterprise customers—especially hybrid and regulated industries—store high‑value data in A...", "status": 500350000, "priority": 172430000, "created": "2026-02-03T19:25:45Z", "modified": "2026-03-18T18:23:38Z", "customers": 0, "impactScore": 5, "keywords": "Data Risk Assessment", "categoryId": null, "crmCustomers": ["BULLETPROOF SOLUTIONS"]}, {"id": "b6e01256-39fd-f011-8406-7c1e52157f8b", "featureId": "MFR-M365-36963", "name": "M365 | Restrict the upload of file to copilot if it contains sensitive data (both OOB SITs as well as Custom SITs)", "description": "Customers need to enforce Microsoft Purview Data Loss Prevention (DLP) policies to block file upload actions in Microsoft 365 Copilot when the content contains sensitive information identified by either built-in or custom Sensitive Information Types (SITs). Today, customers lack a clear and consistent enforcement mechanism to prevent users from uploading files containing sensitive data into Copilot prompts, resulting in a gap between defined DLP policy conditions and Copilot workload enforcement. This limits customers’ ability to apply existing DLP controls to Copilot interactions and ensure s...", "status": 500350000, "priority": 172430000, "created": "2026-01-29T17:38:35Z", "modified": "2026-03-26T15:11:23Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "uatId": "686428", "uatUrl": "https://dev.azure.com/unifiedactiontracker/Technical%20Feedback/_workitems/edit/686428", "crmCustomers": ["Nike"]}, {"id": "224c4942-a6fb-f011-8406-6045bda73be3", "featureId": "MFR-M365-36941", "name": "M365 | DLM: Prevent auto-labelling of shared cloud attachments in Copilot prompt and responses", "description": "Customer who make use of automatic retention label policies to capture and preserve the version shared of modern attachments in Teams, Email and Viva Engage communications require an ability to supress this policy from applying to cloud attachments shared in Copilot prompts and responses.Details on this policy type can be found here:Automatically apply a retention label to Microsoft 365 items | Microsoft Learn Currently any referenced file in a copilot response which is located in SPO triggers the policy and a copy of the file at time of share is stored in the sites Preservation Hold Library.I...", "status": 172430000, "priority": 172430001, "created": "2026-01-27T17:33:15Z", "modified": "2026-03-26T14:16:33Z", "customers": 2, "impactScore": 10, "keywords": "copilot", "categoryId": null, "crmCustomers": ["Barclays Bank plc", "Novartis AG"]}, {"id": "7b258918-71fb-f011-8407-7c1e52157f83", "featureId": "MFR-M365-36928", "name": "Detection and prevention (DLP) of Base64‑encoded data exfiltration using DLP controls for consumer AI apps (e.g. ChatGPT Consumer)", "description": "Detection and prevention (DLP) of Base64‑encoded data exfiltration using DLP controls for consumer AI apps (e.g. ChatGPT Consumer)", "status": 172430000, "priority": 172430000, "created": "2026-01-27T11:12:42Z", "modified": "2026-01-27T11:13:43Z", "customers": 1, "impactScore": 10, "keywords": null, "categoryId": null, "crmCustomers": ["STANDARD CHARTERED BANK"]}, {"id": "62a83e4c-6efb-f011-8407-7c1e52157f83", "featureId": "MFR-M365-36927", "name": "M365 | Detection and prevention (DLP) of Base64‑encoded data exfiltration using DLP controls", "description": "Detection and prevention (DLP) of Base64‑encoded data exfiltration using DLP controls for M365 Copilot", "status": 172430000, "priority": 172430001, "created": "2026-01-27T10:52:43Z", "modified": "2026-03-26T14:12:29Z", "customers": 2, "impactScore": 15, "keywords": null, "categoryId": null, "crmCustomers": ["STANDARD CHARTERED BANK", "INFOSYS LIMITED (Infosys Technologies Limited)"]}, {"id": "63cfc510-63fb-f011-8407-7ced8d17ff64", "featureId": "MFR-M365-36926", "name": "Support iOS for Browser DLP (managed devices)", "description": "Support managed iOS devices for Browser DLP inline data protections.", "status": 172430000, "priority": 172430000, "created": "2026-01-27T09:32:16Z", "modified": "2026-01-27T13:24:37Z", "customers": 2, "impactScore": 27, "keywords": null, "categoryId": null, "crmCustomers": ["PUBLIX SUPER MARKETS INC.", "DNB.NL"]}, {"id": "00880d1d-85f8-f011-8406-7ced8d17ff64", "featureId": "MFR-M365-36903", "name": "P4AI | Item-level data risk assessments to expand beyond 10 sites in the scope", "description": "Looking for item-level data risk assessment to allow you to scan more than the current 10 sites", "status": 500350000, "priority": 172430000, "created": "2026-01-23T17:58:31Z", "modified": "2026-04-03T19:48:15Z", "customers": 2, "impactScore": 18, "keywords": "Data Risk Assessment", "categoryId": null, "crmCustomers": ["Nestle (Nestlé S.A.)", "Siemens Healthineers", "ATEA"]}, {"id": "132d4f47-7cf8-f011-8406-7ced8d17ff64", "featureId": "MFR-M365-36899", "name": "P4AI | Inline browser protection for Use.AI", "description": "Use.ai is a multi-model AI app that's powered by OpenAI, Claude, Grok. Customers are seeing users circumvent ChatGPT protections and using this app instead.", "status": 172430000, "priority": 172430000, "created": "2026-01-23T16:55:11Z", "modified": "2026-01-23T16:55:52Z", "customers": 0, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["BECHTLE"]}, {"id": "30e0414b-66f8-f011-8406-6045bda73be3", "featureId": "MFR-M365-36897", "name": "Purview for A365 | Bulk import of existing Agents into Agent 365 Registry", "description": "Customers with existing registries require a way to import existing agents into the Agent 365 agent registry at scale to enable migration and adoption.", "status": 172430000, "priority": 172430000, "created": "2026-01-23T14:17:50Z", "modified": "2026-03-30T17:09:22Z", "customers": 1, "impactScore": 5, "keywords": "Agent 365", "categoryId": "3fddd600-dac5-f011-bbd3-7c1e5246ae99", "crmCustomers": ["BP (British Petroleum, BP Oil International Ltd, BP Plc)"]}, {"id": "793dfa2d-bef7-f011-8406-6045bdecf97a", "featureId": "MFR-M365-36875", "name": "P4AI | Item-level data risk assessments to take automated actions", "description": "Want automated notifications and actions for item-level assessment. For example, if a file contains sensitive information and is shared with everyone, automatically notify owner and if no action is taken within X# of days, remove the sharing link to help reduce the burden on data security admin.", "status": 500350000, "priority": 172430000, "created": "2026-01-22T18:14:24Z", "modified": "2026-03-18T18:24:29Z", "customers": 0, "impactScore": 6, "keywords": "Data Risk Assessment", "categoryId": null, "crmCustomers": ["ATEA", "THREATSCAPE LIMITED HQ"]}, {"id": "8f93c8c5-bdf7-f011-8406-6045bdecf97a", "featureId": "MFR-M365-36874", "name": "P4AI | Data risk assessments scoped to include or exclude specific SITs", "description": "Want ability to scope data risk assessment to a specific set of SITs and/or exclude or hide certain SITs from the data risk assessment to make the report less noisy.", "status": 500350000, "priority": 172430000, "created": "2026-01-22T18:11:38Z", "modified": "2026-03-23T20:51:59Z", "customers": 0, "impactScore": 13, "keywords": "Data risk assessment", "categoryId": null, "crmCustomers": ["Ravanty Tech Consulting", "THREATSCAPE LIMITED HQ", "ACCENTURE/AVANADE"]}, {"id": "b2e6ba91-93f7-f011-8407-7c1e52817b02", "featureId": "MFR-M365-36873", "name": "Granular scoping for Communication Compliance Policies for AI apps", "description": "Ability to scope communication compliance policies for ethical AI use to more specific app categories or specific apps. Today communication compliance policies can be scoped to “Enterprise AI applications” but customers have a need to exclude Azure Foundry apps from the policy.", "status": 172430000, "priority": 172430000, "created": "2026-01-22T13:09:27Z", "modified": "2026-01-22T13:13:06Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "uatId": "574387", "uatUrl": "https://dev.azure.com/unifiedactiontracker/Technical%20Feedback/_workitems/edit/574387", "crmCustomers": ["BP (British Petroleum, BP Oil International Ltd, BP Plc)"]}, {"id": "fa6e83fe-bff2-f011-8406-6045bda73f33", "featureId": "MFR-M365-36832", "name": "Inline DLP Capability For Copilot in Fabric", "description": "Customer is requesting Inline DLP capability  for Copilot in Fabric and Copilot in PowerBI", "status": 172430000, "priority": 172430000, "created": "2026-01-16T09:44:48Z", "modified": "2026-01-16T09:54:46Z", "customers": 1, "impactScore": 10, "keywords": null, "categoryId": null, "crmCustomers": ["First Bank of Abu Dhabi (FAB)"]}, {"id": "aee60d4a-f6ec-f011-8406-6045bda73f33", "featureId": "MFR-M365-36745", "name": "M365 | \"NOT\" Condition Support in DLP for Copilot Policies", "description": "support for a “NOT” condition within DLP for Copilot policies to allow more granular rule logic. This capability is not blocking their deployment of Copilot or DLP for Copilot; rather, it is a nice‑to‑have enhancement that would improve policy flexibility but is not currently urgent.", "status": 172430000, "priority": 172430000, "created": "2026-01-09T00:58:20Z", "modified": "2026-03-26T14:12:43Z", "customers": 1, "impactScore": 3, "keywords": null, "categoryId": null, "crmCustomers": ["CVS HEALTH"]}, {"id": "a9b787b0-ceec-f011-8406-6045bdda8fbb", "featureId": "MFR-M365-36743", "name": "Purview Devices portal to support Admin Units", "description": "Provide the ability for IT admins who are scoped to an Admin Unit (AU) to see the Devices in Purview's portal for the AU to aid in troubleshooting and onboarding of the Purview solutions Customer is using Admin Units for security boundaries to comply with regulations for industry and GEO.  The Purview IT admins for the US who are scoped to the US Admin unit are not able to view DEVICES for their users or Admin unit, making the Devices portal in the Purview Settings useless to them.   The Devices portal in Purview is adding no value for a large enterprise customers who are using AU features.", "status": 172430000, "priority": 172430000, "created": "2026-01-08T20:15:00Z", "modified": "2026-01-08T20:15:00Z", "customers": 0, "impactScore": null, "keywords": null, "categoryId": null, "crmCustomers": []}, {"id": "18a90437-c3ec-f011-8406-7c1e5246de6f", "featureId": "MFR-M365-36739", "name": "Data Risk Assessments: Add Structured Data Sources to DSPM Oversharing Reports", "description": "Description: \na {\n    text-decoration: none;\n    color: #464feb;\n}\ntr th, tr td {\n    border: 1px solid #e6e6e6;\n}\ntr th {\n    background-color: #f5f5f5;\n}\nEnhance DSPM reporting by including structured data sources in oversharing analysis. This provides a more comprehensive view of data exposure risks across both structured and unstructured environments, improving security posture and compliance. Examples:Oversharing reports currently highlight files in unstructured storage but miss sensitive tables in databases; adding structured sources ensures full coverage.A compliance audit requires visi...", "status": 172430000, "priority": 172430000, "created": "2026-01-08T18:52:48Z", "modified": "2026-04-09T19:22:51Z", "customers": 1, "impactScore": 8, "keywords": null, "categoryId": null, "crmCustomers": ["INSIGHT", "Nationwide"]}, {"id": "dd8831ba-9eec-f011-8407-7c1e52817b02", "featureId": "MFR-M365-36737", "name": "M365 | Block with override for DLP for Copilot", "description": "DLP for Copilot currently supports only block actions. Customers are asking to expand to block with override since there are some instances where users may have legitimate business scenarios to override a block.", "status": 172430000, "priority": 172430000, "created": "2026-01-08T14:31:35Z", "modified": "2026-03-26T14:12:57Z", "customers": 1, "impactScore": 28, "keywords": null, "categoryId": null, "crmCustomers": ["KLOUDYNET TECHNOLOGIES", "SMRT CORPORATION LTD", "Cellenza"]}, {"id": "f160aea1-acdb-f011-8543-6045bdef0457", "featureId": "MFR-M365-36591", "name": "M365 | Copilot prompt DLP to support Advanced Classifiers (including EDM, Trainable Classifiers, Named Entities, etc.)", "description": "If a user types sensitive information containing an Advanced Classifier (EDM, Trainable Classifiers, Named Entities, etc.) into Copilot chat, it should be restricted by DLP.  DLP rules should trigger and block the prompt response.", "status": 172430000, "priority": 172430000, "created": "2025-12-18T00:58:15Z", "modified": "2026-03-26T14:13:09Z", "customers": 3, "impactScore": 55, "keywords": null, "categoryId": null, "crmCustomers": ["Children's Health (Children's Medical Center of Dallas)", "Cleveland Clinic (Cleveland Clinic Foundation)", "CYCLOTRON", "BANQUE CANTONALE DU VALAIS"]}, {"id": "6cafe19b-25d6-f011-8544-6045bdd632b3", "featureId": "MFR-M365-36447", "name": "M365 | Ability to turn off DLP for Copilot Prompt options in MAC", "description": "Customers want Purview capabilities to stay in Purview, they do not want users in MAC to be able to turn on or scope DLP for Copilot prompt policies", "status": 172430000, "priority": 172430000, "created": "2025-12-11T00:09:07Z", "modified": "2026-03-26T14:13:22Z", "customers": 2, "impactScore": 6, "keywords": null, "categoryId": null, "crmCustomers": ["THE HARTFORD", "BRIDGEWATER"]}, {"id": "2372bfed-00d6-f011-8544-7c1e52154f1c", "featureId": "MFR-M365-36444", "name": "Native Purview RAI Reports", "description": "The customer is asking for a native Purview report that shows the prompts sent by users deemed unsafe or non-compliant by RAI. There is nothing out of the box that provides this type of insight, which they are very interested in reporting on. Presently, data has to be exported and paresed through to identify RAI related prompt blocking.This is not currently a blocker, however the customer has asked multiple times for a ways to report on RAI activitiy which may turn into a blocker as there is an active Google Gemini compete.A UAT has been submitted for this ask as well. Feature 547375 Microsoft...", "status": 172430000, "priority": 172430000, "created": "2025-12-10T19:46:35Z", "modified": "2025-12-11T16:22:00Z", "customers": 0, "impactScore": null, "keywords": null, "categoryId": null, "crmCustomers": []}, {"id": "3a9b5bbb-e4d5-f011-8544-6045bdd632b3", "featureId": "MFR-M365-36436", "name": "Surface RAI Blocks in DSPM Activity Explorer", "description": "Surface RAI blocks in activity explorer so that admin know when users are attempting to maliciously use Copilot or other AI apps/agents", "status": 172430000, "priority": 172430000, "created": "2025-12-10T16:24:43Z", "modified": "2025-12-11T16:26:11Z", "customers": 1, "impactScore": 3, "keywords": null, "categoryId": null, "crmCustomers": ["Wells Fargo (WELLS FARGO & COMPANY)"]}, {"id": "a6a612ca-29d5-f011-8544-6045bda91a4a", "featureId": "MFR-M365-36420", "name": "M365 | Policy Tip Support for M365 Prompt DLP", "description": "CX-need: Enable policy tips (warning messages) for users in Microsoft 365 Copilot when sensitive data is detected via DLP policies.   Description:While setting up DLP policies in Purview, it is possible for admins to add a policy tip under \" actions\" . However, when M365 Copilot is selected as scope, the actions tab only provides the ability to impose restriction from processing and not the ability to add a warning / policy tip. Help is needed to bring this feature to production. Customer Scenario:Ability to warn users while dealing with sensitive data in M365 Copilot", "status": 172430000, "priority": 172430000, "created": "2025-12-09T18:06:37Z", "modified": "2026-03-26T14:13:35Z", "customers": 2, "impactScore": 20, "keywords": null, "categoryId": null, "uatId": "646707", "uatUrl": "https://dev.azure.com/unifiedactiontracker/Technical%20Feedback/_workitems/edit/646707", "crmCustomers": ["DNB.NL", "KLOUDYNET TECHNOLOGIES", "SMRT CORPORATION LTD"]}, {"id": "674f267c-1ad5-f011-8544-7c1e520b6b67", "featureId": "MFR-M365-36419", "name": "DSPM | Ability to export all prompts and responses through an API to an external SIEM", "description": "Customer would like these exposed via one of our API's so that they can catalogue and pull them up in their SIEM as apart of threat analysis without having to send resources into DSPM for AI to dig for them manually.", "status": 500350002, "priority": 172430000, "created": "2025-12-09T16:16:58Z", "modified": "2026-03-26T14:59:14Z", "customers": 0, "impactScore": null, "keywords": null, "categoryId": null, "crmCustomers": []}, {"id": "c91ce3ff-fad0-f011-8544-6045bda91a4a", "featureId": "MFR-M365-36356", "name": "Browser DLP: support for policy tips", "description": "Enhancement to inline policy session They would like in-line customizable policy tips (logo, custom text etc) to appear when the user takes blocked actions, such as trying to copy paste. This is for unmanaged device scenario.", "status": 172430000, "priority": 172430000, "created": "2025-12-04T10:21:31Z", "modified": "2025-12-04T10:26:05Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "uatId": "528684", "uatUrl": "https://dev.azure.com/unifiedactiontracker/Technical%20Feedback/_workitems/edit/528684", "crmCustomers": ["WPP"]}, {"id": "f1517319-f7d0-f011-8544-6045bda91a4a", "featureId": "MFR-M365-36355", "name": "Purview for A365 | Include Agent Name when using PowerShell to export from Activity Explorer", "description": "there is a limitation of 10000 items when exporting activities via the web UI. So to overcome that, customer uses PowerShell (Export-ActivityExplorerData), however there are two limitations:The API only allows retrieving data from last 30 days (whilst our web UI allows up to 180 days)The Agent Name / ID are not included in the outputThe desired outcome is allowing Copilot Admin being able to view Agent usage data in MAC because at the moment they can only view the list of agents built with Agent Builder, but cannot tell who and how many are using them.", "status": 172430000, "priority": 172430000, "created": "2025-12-04T09:53:38Z", "modified": "2026-03-30T17:09:45Z", "customers": 1, "impactScore": 3, "keywords": null, "categoryId": null, "uatId": "614396", "uatUrl": "https://dev.azure.com/unifiedactiontracker/Technical%20Feedback/_workitems/edit/614396", "crmCustomers": ["COMMONWEALTH BANK OF AUSTRALIA"]}, {"id": "3b17ce41-f6d0-f011-8544-6045bda91a4a", "featureId": "MFR-M365-36354", "name": "DSPM for AI activity explorer timestamps should be localized", "description": "Timestamps are currently shown in UTC.  :SOC analysts need to quickly and reliably work out what time an issue arose. Displaying times localized by the Defender time zone preference is ideal. Across Defender/Purview sub-portals, there's a mix of timestamps in UTC and local TZ, for activity and alerts impacting the investigation experience via two portals.", "status": 172430000, "priority": 172430000, "created": "2025-12-04T09:47:36Z", "modified": "2025-12-04T09:50:34Z", "customers": 1, "impactScore": 3, "keywords": null, "categoryId": null, "uatId": "631568", "uatUrl": "https://dev.azure.com/unifiedactiontracker/Technical%20Feedback/_workitems/edit/631568", "crmCustomers": ["COLES SUPERMARKETS PTY LTD"]}, {"id": "d36bbbdb-a2cf-f011-8544-6045bdd632b3", "featureId": "MFR-M365-36329", "name": "Include \"unlabeled\" as a condition in a DLP for Copilot policy", "description": "Customers request a new option in Data Loss Prevention (DLP) Copilot to exclude unlabeled documents from Copilot processing in SharePoint Online (SPO). This would allow customers to ensure that only labeled documents are processed, addressing challenges with large volumes of unlabeled files and auto-labeling throttling limits.", "status": 500350012, "priority": 172430000, "created": "2025-12-02T17:18:03Z", "modified": "2026-03-26T13:18:54Z", "customers": 0, "impactScore": 0, "keywords": null, "categoryId": null, "crmCustomers": ["BNP Paribas (BNPP)", "BANQUE CANTONALE DU VALAIS"]}, {"id": "81d85c8f-f1ce-f011-8544-7c1e526b516b", "featureId": "MFR-M365-36311", "name": "P4AI | Purview AI controls for Salesforce Einstein", "description": "Customers want to detect and block AI usage within Salesforce Einstein to prevent and/or block sensitive data exposure within this 3P AI SaaS app.", "status": 172430000, "priority": 172430000, "created": "2025-12-01T20:08:58Z", "modified": "2025-12-01T20:10:09Z", "customers": 1, "impactScore": 21, "keywords": null, "categoryId": null, "crmCustomers": ["ECOLAB  (Ecolab Inc)", "PROTIVITI (Robert Half)"]}, {"id": "84dfa03d-f1ce-f011-8544-7c1e526b516b", "featureId": "MFR-M365-36310", "name": "P4AI | Purview AI controls for Mistral AI", "description": "Customers want to detect and block AI usage within Mistral AI to prevent and/or block sensitive data exposure within this 3P AI SaaS app.", "status": 172430000, "priority": 172430000, "created": "2025-12-01T20:06:37Z", "modified": "2026-01-23T16:53:58Z", "customers": 1, "impactScore": 9, "keywords": null, "categoryId": null, "crmCustomers": ["DEVENSYS CYBERSECURITY", "VORSTONE", "BECHTLE"]}, {"id": "79452dc3-dcca-f011-8544-6045bda91a4a", "featureId": "MFR-M365-36268", "name": "Azure Copilot Support in Purview for AI", "description": "Microsoft Purview DSPM for AI, integrated with Microsoft Copilot in Azure, to ensure visibility and protection for Copilot in Azure.", "status": 172430000, "priority": 172430000, "created": "2025-11-26T15:30:05Z", "modified": "2026-02-27T14:29:01Z", "customers": 2, "impactScore": 10, "keywords": null, "categoryId": null, "uatId": "645717", "uatUrl": "https://dev.azure.com/unifiedactiontracker/Technical%20Feedback/_workitems/edit/645717", "crmCustomers": ["Nestle (Nestlé S.A.)", "EDWARD D JONES AND COMPANY (Edward Jones Investments)"]}, {"id": "1d9e9f29-d5ca-f011-8544-6045bda91a4a", "featureId": "MFR-M365-36267", "name": "Browser Data Security: support Baidu", "description": "Customer wants to see what and who interacts with chinese AI App Baidu. Therefor listing it in DSPM for AI is necessary", "status": 172430000, "priority": 172430000, "created": "2025-11-26T14:35:33Z", "modified": "2025-11-26T14:38:14Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["Drägerwerk AG & Co. KGaA"]}, {"id": "ad9d9ec9-bbca-f011-8544-6045bda91a4a", "featureId": "MFR-M365-36265", "name": "Data risk assessments: finer grained controls for what is overshared", "description": "Customers want finer grained controls for defining what is overshared. For example documents with SITs showing up a certain number of times are shared with X number of users.  Zscaler offer this capability (fine-grained, condition-based detection).", "status": 172430000, "priority": 172430000, "created": "2025-11-26T11:33:54Z", "modified": "2026-03-26T20:54:51Z", "customers": 1, "impactScore": 25, "keywords": null, "categoryId": null, "uatId": "609245", "uatUrl": "https://unifiedactiontracker.visualstudio.com/Technical%20Feedback/_workitems/edit/609245", "crmCustomers": ["Adecco Group AG", "ACCENTURE/AVANADE", "Ravanty Tech Consulting", "THREATSCAPE LIMITED HQ", "PROTIVITI (Robert Half)"]}, {"id": "69eb6760-42c6-f011-bbd3-6045bda91a4a", "featureId": "MFR-M365-36230", "name": "Azure Foundry integration- support user context details for non-Entra Authentication", "description": "Purview DSPM for AI Activity Explorer is showing M365 licensed user Azure Foundry AI Activity as Guest interactions because P4AI only identifies users from the AI Apps where user context is passed part of the Entra Authentication. P4AI Integration needs to identify users by their UPN (Email) if using non-Entra Auth or not passing the user context", "status": 172430000, "priority": 172430000, "created": "2025-11-20T18:54:44Z", "modified": "2026-03-13T16:03:56Z", "customers": 3, "impactScore": 30, "keywords": null, "categoryId": null, "uatId": "602390", "uatUrl": "https://dev.azure.com/unifiedactiontracker/Technical%20Feedback/_workitems/edit/602390/?view=edit", "crmCustomers": ["BP (British Petroleum, BP Oil International Ltd, BP Plc)", "Corning Inc.", "LENOVO", "ARMIS GROUP"]}, {"id": "4114c124-41c6-f011-bbd3-6045bda91a4a", "featureId": "MFR-M365-36229", "name": "DLP support for trainable classifiers on violence and weapons supported for Azure Foundry apps", "description": "For Azure Foundry apps and agents, DLP support is needed for trainable classifiers on violence and weapons, so customers can block and add a policy tip around correct language for legitimate non violent prompts.", "status": 172430000, "priority": 172430000, "created": "2025-11-20T18:46:00Z", "modified": "2025-11-20T18:48:38Z", "customers": 1, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["Department for Environment Food & Rural Affairs (DEFRA)"]}, {"id": "090cc150-3dc6-f011-bbd3-6045bda91a4a", "featureId": "MFR-M365-36228", "name": "GitHub Copilot support for DSPM for AI", "description": "Support GitHub Copilot in Purview for AI.", "status": 172430000, "priority": 172430000, "created": "2025-11-20T18:18:35Z", "modified": "2026-04-16T16:54:12Z", "customers": 8, "impactScore": 72, "keywords": null, "categoryId": null, "uatId": "589021", "uatUrl": "https://dev.azure.com/unifiedactiontracker/Technical%20Feedback/_workitems/edit/589021", "crmCustomers": ["KT Corporation (Korea Telecom)", "HYUNDAI MOTOR AND KIA", "American Express (AMEX, AEXP, AXP)", "STANDARD CHARTERED BANK", "EVEREST REINSURANCE", "AT&T", "LG전자", "EY (Ernst & Young)", "Shell (Royal Dutch Shell)"]}, {"id": "e47b340e-dac5-f011-bbd3-7c1e5246ae99", "featureId": "MFR-M365-36225", "name": "Scope DSPM for AI Collection Policies to Include or Exclude Specific SITs", "description": "Customers need the ability to Capture Content by select/exclude specific SITs in the collection policies to reduce noise and unwanted SITs detections for Enterprise AI Apps and Copilot Experiences", "status": 500350002, "priority": 172430001, "created": "2025-11-20T06:27:59Z", "modified": "2026-02-27T14:47:18Z", "customers": 4, "impactScore": 30, "keywords": null, "categoryId": "3fddd600-dac5-f011-bbd3-7c1e5246ae99", "uatId": "631873", "uatUrl": "https://uatracker.microsoft.com/action?id=631873", "crmCustomers": ["COLES SUPERMARKETS PTY LTD", "DNB.NL", "MORGAN STANLEY SERVICES GROUP INC. (Morgan Stanley, MORGANSTANLEYANDCO)", "LTIMINDTREE"]}, {"id": "862411ed-3cbf-f011-bbd3-7c1e520d7246", "featureId": "MFR-M365-36137", "name": "Purview for A365 | Visibility into ALL agents in the tenant", "description": "Remove the 20-item limit in DSPM for AI’s Apps & Agents view and add ownership attribution (user who created each app/agent) to enable full governance and accountability. UAT: Feature 623399 Purview: Expand DSPM for AI Apps & Agents View with Full Ownership Details.", "status": 500350008, "priority": 172430000, "created": "2025-11-11T20:28:05Z", "modified": "2026-03-30T17:10:14Z", "customers": 2, "impactScore": 28, "keywords": null, "categoryId": null, "crmCustomers": ["Nestle (Nestlé S.A.)", "Cleveland Clinic (Cleveland Clinic Foundation)"]}, {"id": "6238495a-3cbf-f011-bbd3-7c1e520d7246", "featureId": "MFR-M365-36136", "name": "Purview for A365 | Unpublish Agents from Purview", "description": "Customers would like the ability to unpublish agents from Purview based on how risky the user's behavior is, the riskiness of the agent, what it has access to and if it is published to too many people. They do not want the publish/unpublish duties to just be on the IT admin.", "status": 172430000, "priority": 172430000, "created": "2025-11-11T20:24:01Z", "modified": "2026-03-30T17:10:33Z", "customers": 1, "impactScore": 15, "keywords": null, "categoryId": null, "crmCustomers": ["Cleveland Clinic (Cleveland Clinic Foundation)"]}, {"id": "5194dc30-3bbf-f011-bbd3-7c1e520d7246", "featureId": "MFR-M365-36135", "name": "Purview for A365 | Agent Knowledge Source Visibility", "description": "Customers would like visibility into the agents’ knowledge sources to determine if the agent has access to excessive sensitive data in relation to the users authorized to interact with them. Our understanding is that this will be added into agent observability, but we have not been able to test to confirm the details of the capability.", "status": 500350008, "priority": 172430000, "created": "2025-11-11T20:15:44Z", "modified": "2026-03-30T17:10:55Z", "customers": 3, "impactScore": 25, "keywords": null, "categoryId": null, "crmCustomers": ["Cleveland Clinic (Cleveland Clinic Foundation)", "Nestle (Nestlé S.A.)", "BP (British Petroleum, BP Oil International Ltd, BP Plc)"]}, {"id": "41b914af-38bf-f011-bbd3-7c1e520d7246", "featureId": "MFR-M365-36134", "name": "Purview for A365 | Categorize AI Apps/Agents", "description": "Customers would like to see similar capabilities to Netskope - categorizing agents such as (writing tools, conversational agents, etc.)", "status": 172430000, "priority": 172430000, "created": "2025-11-11T19:57:43Z", "modified": "2026-03-30T17:11:21Z", "customers": 0, "impactScore": null, "keywords": null, "categoryId": null, "crmCustomers": []}, {"id": "ae34d661-36bf-f011-bbd3-7c1e520d7246", "featureId": "MFR-M365-36133", "name": "M365 | Visibility into Copilot Interaction Themes", "description": "Visibility into themes of Copilot conversations within DSPM for AI reports and Activity Explorer. Specifically, they want categorization of actions such as summarization, research queries, or non-work-related prompts. This insight would help organizations measure Copilot adoption, inform license extension decisions, and apply appropriate restrictions. Leadership views this as critical for understanding usage patterns and driving governance.", "status": 172430000, "priority": 172430000, "created": "2025-11-11T19:41:17Z", "modified": "2026-03-26T14:14:06Z", "customers": 1, "impactScore": 15, "keywords": null, "categoryId": null, "crmCustomers": ["Cleveland Clinic (Cleveland Clinic Foundation)"]}, {"id": "a0cb4a67-32bf-f011-bbd3-7c1e520d7246", "featureId": "MFR-M365-36131", "name": "Extend Browser DLP Support to Chrome", "description": "Extend Browser inline DLP support to Chrome", "status": 172430000, "priority": 172430000, "created": "2025-11-11T19:12:46Z", "modified": "2026-03-25T13:34:48Z", "customers": 8, "impactScore": 76, "keywords": null, "categoryId": null, "crmCustomers": ["Cleveland Clinic (Cleveland Clinic Foundation)", "INTESA SAN PAOLO", "DIALOG GROUP", "MICHAELS STORES INC", "Nestle (Nestlé S.A.)", "Threatscape", "BAKER HUGHES", "NGAN HANG TMCP QUAN DOI (MBBANK)"]}, {"id": "8dd7c0bc-38b3-f011-bbd3-7c1e5246ae99", "featureId": "MFR-M365-35968", "name": "P4AI | Catalog ChatGPT Enterprise interactions in Data Catalog", "description": "Catalog prompts and responses from ChatGPT Enterprise to appear as discoverable, browsable assets in Purview Data Catalog. This ensures that conversational AI artifacts are treated like other governed data assets, enabling search, classification, lineage and policy enforcement.", "status": 172430000, "priority": 172430000, "created": "2025-10-27T13:27:55Z", "modified": "2025-10-27T13:28:55Z", "customers": 0, "impactScore": 3, "keywords": null, "categoryId": null, "crmCustomers": ["SLALOM CONSULTING"]}, {"id": "02125eaa-01a9-f011-bbd3-6045bdd4220a", "featureId": "MFR-M365-35841", "name": "P4AI | Add \"Last Modified\" column in Data Risk Assessment", "description": "Add “Last Modified” column to DSPM for AI Data Risk Assessment reports to help organizations understand how active a file is and to prioritize remediation for active, high-risk sensitive data. Intellectual property, mergers, acquisitions data are typically active and high risk. The current report lacks context on data freshness, making it hard to distinguish stale and active sensitive files.", "status": 172430000, "priority": 172430000, "created": "2025-10-14T13:28:34Z", "modified": "2025-10-14T13:29:21Z", "customers": 0, "impactScore": 3, "keywords": null, "categoryId": null, "crmCustomers": ["ACCENTURE/AVANADE"]}, {"id": "832e3355-00a9-f011-bbd3-6045bdd4220a", "featureId": "MFR-M365-35840", "name": "M365 | Pre-trained ML classifier to detect data-hunting behavior in AI apps", "description": "Pre-trained ML classifier that identifies when a user is attempting to hunt for sensitive data in AI apps. The classifier should detect intent in queries such as: “what sensitive information can I access\", “show me all files marked confidential”, “list documents with financial data”. Customer could then set up IRM/CC policies to flag these kinds of queries or trigger DLP policy-based actions.", "status": 172430000, "priority": 172430000, "created": "2025-10-14T13:18:55Z", "modified": "2026-03-26T13:20:11Z", "customers": 5, "impactScore": 78, "keywords": null, "categoryId": null, "crmCustomers": ["ACCENTURE/AVANADE", "TELADOC HEALTH", "Move AS", "EY (Ernst & Young)", "ECOLAB  (Ecolab Inc)", "VORSTONE", "INSIGHT", "RAPID CIRCLE", "INCREMENT PTY LTD", "Nitec Solutions", "ADASTRA GROUP", "SPARK NEW ZEALAND", "ENERGIZER", "DEVENSYS CYBERSECURITY", "ATEA"]}, {"id": "99cbfdc2-e1a5-f011-bbd3-7c1e526b516b", "featureId": "MFR-M365-35825", "name": "Surface attempts to jailbreak Copilot or its agents in DSPM for AI.", "description": "Nestle’s request to surface attempts to jailbreak Copilot or its agents in DSPM for AI's activity explorer.Reasoning: Untracked unethical behavior poses significant security and compliance risks. Without visibility into these attempts, organizations cannot respond to threats or enforce ethical use. It’s important for them to have visibility of Jailbreak attempts in DSPM for AI. They have also tried using CC policies but it generates too many false positives.", "status": 172430000, "priority": 172430001, "created": "2025-10-10T14:02:35Z", "modified": "2025-10-10T14:37:41Z", "customers": 1, "impactScore": 0, "keywords": null, "categoryId": null, "crmCustomers": ["Nestle (Nestlé S.A.)"]}, {"id": "a308e98d-1fa5-f011-bbd3-6045bdecc3ee", "featureId": "MFR-M365-35803", "name": "Purview E5C Pre-req | Add Business Premium", "description": "Distributor partners want to leverage the E5C trial to drive upsell for Purview Suite that’s now available to Business Premium customers, tying to M365 Copilot adoption. The current pre-req for E5C trial pilot is E3 and above.  Opportunity: We have 10 Distributors and several MSPs who wants to leverage the DSPM feature in E5C to drive upsell discussion with their BP customers.  8.1M Business Premium paid seats with just the 10 Distributors we are engaged with and potentially more if we make this available in Partner Center for all CSP partners.  Issue: The current pre-requisite licenses are on...", "status": 172430000, "priority": 172430000, "created": "2025-10-09T14:52:24Z", "modified": "2025-10-23T12:44:27Z", "customers": 0, "impactScore": 0, "keywords": null, "categoryId": null, "crmCustomers": ["ALSO", "Arrow (Sweden)", "TD Synnex", "DICKER DATA", "Crayon", "REDINGTON", "Be Cloud", "SHERWEB", "Pax8 (US)", "MSP Operational Corp", "Ingram Micro (Canada)"]}, {"id": "26a0c317-c898-f011-b41c-6045bdffdb47", "featureId": "MFR-M365-35655", "name": "M365 | Enable DLP Alerts for Blocked Actions in M365 Copilot", "description": "Produce an alert in the Purview DLP portal when DLP for M365 copilot is 'blocking' user access. Lack of alerts doesn't meet customers business reguirements for  DLP for M365 Copilot to be deployed at scale.'Alerts' are missing when DLP for copilot is 'blocking' user access", "status": 172430000, "priority": 172430000, "created": "2025-09-23T21:56:01Z", "modified": "2026-03-26T14:09:46Z", "customers": 3, "impactScore": 51, "keywords": null, "categoryId": null, "crmCustomers": ["CENTENE CORPORATION", "GMAC (Ally Financial)", "Johnson Controls Inc (JCI)"]}, {"id": "52eb9829-b994-f011-b4cb-7ced8d17c5da", "featureId": "MFR-M365-35610", "name": "Monitor personal account use of 3P AI", "description": "Monitor users accessing 3P AI on managed work devices. Track if they are inputting sensitive data and what the prompts/responses are.", "status": 172430000, "priority": 172430000, "created": "2025-09-18T17:59:08Z", "modified": "2025-09-18T17:59:39Z", "customers": 1, "impactScore": 0, "keywords": null, "categoryId": null, "crmCustomers": ["Cleveland Clinic (Cleveland Clinic Foundation)"]}, {"id": "f5b451b7-b894-f011-b4cb-7ced8d17c5da", "featureId": "MFR-M365-35609", "name": "Prompt DLP support for Copilot in Fabric", "description": "Block/exclude processing responses based on SIT (prompt DLP) will also cover PBI Copilot", "status": 172430000, "priority": 172430000, "created": "2025-09-18T17:55:53Z", "modified": "2025-09-18T17:56:29Z", "customers": 1, "impactScore": 0, "keywords": null, "categoryId": null, "crmCustomers": ["AT&T"]}, {"id": "5f44a3c4-518f-f011-b4cb-7ced8d17c5da", "featureId": "MFR-M365-35549", "name": "M365 | SIT classification assign label to unlabeled files uploaded to M365 Copilot", "description": "SIT classification to assign a sensitivity label to unlabeled files that are uploaded to M365 Copilot", "status": 172430000, "priority": 172430000, "created": "2025-09-11T20:56:25Z", "modified": "2026-04-02T13:22:49Z", "customers": 1, "impactScore": 0, "keywords": null, "categoryId": null, "crmCustomers": ["RAYTHEON TECHNOLOGIES"]}, {"id": "7b04ad04-f489-f011-b4cc-7c1e5246a79a", "featureId": "MFR-M365-35495", "name": "M365 | DLP Block Web Query, Allow Work Mode", "description": "Ability to block the web query from being sent but allow Copilot to still process a response through work mode", "status": 172430006, "priority": 172430000, "created": "2025-09-05T01:02:48Z", "modified": "2026-03-26T14:15:06Z", "customers": 4, "impactScore": 3, "keywords": null, "categoryId": null, "crmCustomers": ["NatWest", "Corning Inc.", "JP Morgan Chase (JPMC)", "Goldman Sachs"]}, {"id": "65ef2b13-f389-f011-b4cc-7c1e5246a79a", "featureId": "MFR-M365-35494", "name": "M365 | DLP for Grounding Data containing SITs", "description": "Supporting unlabeled files containing SITs in the grounding data", "status": 500350000, "priority": 172430000, "created": "2025-09-05T00:56:02Z", "modified": "2026-03-26T14:15:18Z", "customers": 4, "impactScore": 5, "keywords": null, "categoryId": null, "crmCustomers": ["THE HARTFORD", "IHG", "DuPont", "BANQUE CANTONALE DU VALAIS"]}, {"id": "e3362729-9b89-f011-b4cc-7c1e5246a79a", "featureId": "MFR-M365-35489", "name": "M365 | DLM Policy to Scope based on SITs", "description": "DLM Capability to be able to delete AI Interactions that have Sensitive detections (SITs) per Location scoped to give AI App/Agent or Copilot. For example, customers don’t want a prompt sitting with an SSN sitting in audit logs for 5 years", "status": 172430000, "priority": 172430000, "created": "2025-09-04T14:26:41Z", "modified": "2026-03-26T14:15:33Z", "customers": 2, "impactScore": 0, "keywords": null, "categoryId": null, "crmCustomers": ["Asurion, LLC", "Marsh & McLennan"]}, {"id": "c20000ae-9889-f011-b4cc-7c1e5246a79a", "featureId": "MFR-M365-35488", "name": "M365 | Redact SITs from Copilot response", "description": "First step was blocking based on label on referenced file, then prompt DLP based on SITs in the prompt. Customers are now asking for SITs to be redacted in the response so end users aren't returned SITs.", "status": 500350008, "priority": 172430000, "created": "2025-09-04T14:08:52Z", "modified": "2026-04-21T11:24:07Z", "customers": 4, "impactScore": 53, "keywords": null, "categoryId": null, "crmCustomers": ["ACCENTURE/AVANADE", "Insight (UK)", "PROTIVITI (Robert Half)", "COMMONWEALTH BANK (Commonwealth Bank of Australia/CBA, CBA)", "ING", "American Express (AMEX, AEXP, AXP)"]}, {"id": "661847f8-9789-f011-b4cc-7c1e5246a79a", "featureId": "MFR-M365-35486", "name": "Purview for A365 | Scope DLP policies per App/Agent Name", "description": "", "status": 172430000, "priority": 172430000, "created": "2025-09-04T14:03:47Z", "modified": "2026-04-09T12:28:21Z", "customers": 6, "impactScore": 64, "keywords": null, "categoryId": null, "crmCustomers": ["Corning Inc.", "BP (British Petroleum, BP Oil International Ltd, BP Plc)", "KPMG", "American Express (AMEX, AEXP, AXP)", "MICROSOFT CORPORATION", "LSEG"]}, {"id": "77c7952e-7983-f011-b4cc-7c1e520d7abd", "featureId": "MFR-M365-35419", "name": "M365 | Prompt DLP: Ability to customize end user notifications", "description": "Customers would like to be able to customize the notifications that are sent to end users when prompt DLP takes place. Including the ability to add links.", "status": 500350000, "priority": 172430000, "created": "2025-08-27T19:08:21Z", "modified": "2026-03-26T14:16:05Z", "customers": 13, "impactScore": 120, "keywords": null, "categoryId": null, "uatId": "591094", "uatUrl": "https://dev.azure.com/unifiedactiontracker/Technical%20Feedback/_workitems/edit/591094/?view=edit", "crmCustomers": ["CHANEL SAS", "BP (British Petroleum, BP Oil International Ltd, BP Plc)", "ETISALAT", "Accenture", "KPMG", "BAKERHOSTETLER", "KIRKLAND ELLIS (Kirkland and Ellis, Kirkland & Ellis)", "SOUTH GLOUCESTERSHIRE COUNCIL", "Wolters Kluwer (WOLTERS KLUWER USA)", "CVS HEALTH", "AT&T", "MICROSOFT CORPORATION (CSEO, former MSIT)", "NVIDIA Corporation"]}, {"id": "671034cc-7883-f011-b4cc-7c1e520d7abd", "featureId": "MFR-M365-35418", "name": "M365 | Prompt DLP Support for Copilot", "description": "Ability to block Copilot response / web query when the Prompt contains SITs", "status": 172430007, "priority": 172430000, "created": "2025-08-27T19:05:36Z", "modified": "2026-03-26T14:16:20Z", "customers": 7, "impactScore": 36, "keywords": null, "categoryId": null, "crmCustomers": ["CVS HEALTH", "AT&T", "NVIDIA Corporation", "Corning Inc.", "MICROSOFT CORPORATION", "American Express (AMEX, AEXP, AXP)", "Global Payments"]}, {"id": "1b16bd34-6c7c-f011-b4cc-6045bdf0ef76", "featureId": "MFR-M365-35335", "name": "M365 Copilot | Clear Differentiation Needed for Copilot Activities in Purview Audit", "description": "Clarify the different activities related to Copilot (Microsoft Copilot Chat , Microsoft 365 Copilot ) There is a lot of unclarity when customer want to select Copilot activities when creating an Audit request. The tool is unpractical and nearly useless. See included picture.", "status": 500350002, "priority": 172430000, "created": "2025-08-18T19:47:44Z", "modified": "2026-03-26T14:10:50Z", "customers": 0, "impactScore": null, "keywords": null, "categoryId": null, "crmCustomers": []}, {"id": "1a821828-f576-f011-b4cc-7ced8d17c5da", "featureId": "MFR-M365-35291", "name": "M365 | Unable to detect Sensitive Information Types (SITs) in M365 Copilot DLP", "description": "Ability to use Sensitive Information Types or SITs in the M365 Copilot DLP PolicyInvite for Private Preview to validate the featureCustomer is in preview using M365 Copilot DLP and they are not able to use Sensitive Information Types or SITs in the Copilot DLP Policy. They are using Sensitivity labels but also require SITs for their regulation  The opened a support case and were told it's not available In talking with Engineering, a private preview is not available", "status": 500350012, "priority": 172430000, "created": "2025-08-11T20:52:57Z", "modified": "2026-03-26T15:01:21Z", "customers": 0, "impactScore": 0, "keywords": null, "categoryId": null, "crmCustomers": ["ALLEN & OVERY"]}, {"id": "0e509eb9-ee76-f011-b4cc-7ced8d17c5da", "featureId": "MFR-M365-35290", "name": "M365 | Copilot Prompt DLP - Extend to On-Prem Labeled Data", "description": "They would be able to specify labels that are extended to on-premises documents to prevent any interaction with copilot whether it is embedded (word, excel, power point) or uploaded to chat functionality. Performing similar to cloud saved documents (ODfb/SPO). A UK Consultancy Company that has contracts with export controls and official sensitive information handling standards requiring certain data to remain on-premise due to various regulations has enabled Copilot Prompt DLP and verified it does work for online file types but when using native embedded experiences does not block copilot prom...", "status": 172430006, "priority": 172430000, "created": "2025-08-11T20:06:58Z", "modified": "2026-03-30T17:12:30Z", "customers": 0, "impactScore": null, "keywords": null, "categoryId": null, "crmCustomers": []}, {"id": "b3ab9f80-eb76-f011-b4cc-7ced8d17c5da", "featureId": "MFR-M365-35284", "name": "M365 | Outlook Copilot enforcement of restricted sensitivity labels for email summarization", "description": "Outlook honors the sensitivity label set for 'prevent processing' inside DLP for M365 Copilot rule that is enabledEmail is a common tool used for data exfiltration attempts Customer is using DLP for M365 Copilot and noticed that emails labeled with restricted sensitivity labels are still able to be summarized, this is concerning to them as they deploy M365 Copilot", "status": 500350008, "priority": 172430000, "created": "2025-08-11T19:43:51Z", "modified": "2026-03-26T15:07:50Z", "customers": 3, "impactScore": 0, "keywords": null, "categoryId": null, "crmCustomers": ["Blackrock (BLACKROCK FINANCIAL MANAGEMENT)", "Micron Technology Inc.", "CIBC (Canadian Imperial Bank of Commerce)"]}, {"id": "853680a3-e476-f011-b4cc-7ced8d17c5da", "featureId": "MFR-M365-35278", "name": "M365 | Expand DSPM for AI recommendations to cover Communication Compliance for Copilot interactions", "description": "Include CC policy \"Microsoft 365 Copilot Interactions\" as part of DSPM for AI recommendations. Discussed this with Sophie Ke already.DSPM for AI recommends a number of AI related policies across Purview, including one for Communication Compliance \"Detect unethical behavior in AI apps\" but it doesn't include what I believe to be the most relevant CC policy \"Microsoft 365 Copilot Interactions\" which targets Copilot Experiences, using the Azure AI classifiers Prompt Shields, Protected material and to detect risky usage of Copilot.", "status": 500350009, "priority": 172430000, "created": "2025-08-11T18:54:49Z", "modified": "2026-03-26T15:08:58Z", "customers": 2, "impactScore": 0, "keywords": null, "categoryId": null, "crmCustomers": ["QATAR POST", "Johnson Controls Inc (JCI)"]}, {"id": "7b0c9b6c-9261-f011-bec1-6045bdffdb47", "featureId": "MFR-M365-35068", "name": "M365 | Restrict Copilot Access in GCC via Sensitivity Labels and DLP Polices", "description": "Customer is concerned about data protection and oversharing and ensuring that sensitive data can be isolated from Copilot in the most efficient manner possible.  The customer would like to use Microsoft Purview Sensitivity Labels in conjunction with Data Loss Prevention (DLP) policies in GCC to prevent Microsoft Copilot from accessing or retrieving data that is protected by these labels and policies. Their goal is to ensure that Copilot cannot search or surface content that has been classified and restricted under these compliance controls.", "status": 172430000, "priority": 172430000, "created": "2025-07-15T15:43:17Z", "modified": "2026-03-26T15:09:53Z", "customers": 0, "impactScore": null, "keywords": null, "categoryId": null, "crmCustomers": []}, {"id": "f40826b1-ff3b-f011-b4cc-6045bda7d206", "featureId": "MFR-M365-34646", "name": "AI Generated Sensitivity Labels in Purview", "description": "Customer would like to be able to label the content as \"AI generated\". Not the entire document (they are happy with Label Inheritance) but something along the lines of \"This content was generated from a confidential document.\" This will change the label of the document to \"Confidential\" and restrict access. Do you want to proceed?\" Similar to DLP Tips but for AI generated content.", "status": 172430000, "priority": 172430000, "created": "2025-05-28T20:09:43Z", "modified": "2025-06-30T07:59:09Z", "customers": 1, "impactScore": 6, "keywords": null, "categoryId": null, "crmCustomers": ["NACELLE IT"]}, {"id": "ec8b4ccf-0131-f011-8c4e-7c1e524627f8", "featureId": "MFR-M365-34544", "name": "M365 | DLP for Copilot - PDF/Filetype support not mentioned in any documentation", "description": "Update the public documentation to list filetype support for this feature. It is called out specifically on the NDA roadmap slide deck, but that is the only place I have been able to find that information.Link to NDA roadmap: Data Security NDA roadmap on slide 8:\"DLP: Extension of DLP controls to M365 Copilot, starting with policy conditions to prevent processing of Office files & PDFs in SharePoint with a sensitivity label applied\"No where in our public documentation or internal wiki docs do we mention PDF or filetype support for DLP for CoPilot. Internal resources we checked and didn't find ...", "status": 500350004, "priority": 172430000, "created": "2025-05-14T20:27:15Z", "modified": "2026-03-26T15:10:35Z", "customers": 4, "impactScore": 73, "keywords": null, "categoryId": null, "crmCustomers": ["Pricewaterhouse Coopers (PWC, PricewaterhouseCoopers LLP)", "Blackrock (BLACKROCK FINANCIAL MANAGEMENT)", "CONSULCESI", "CHARLES TAYLOR PLC"]}, {"id": "a0d22f89-2f00-f011-bae3-7c1e524a5d40", "featureId": "MFR-M365-33812", "name": "Activity Explorer: When click on Risky user details, direct to user in IRM", "description": "When you click on a user details in Activity Explorer, it should take you directly to that user page in IRM to investigate. Instead it just takes you to IRM.", "status": 172430000, "priority": 172430000, "created": "2025-03-13T17:21:08Z", "modified": "2025-03-13T17:22:00Z", "customers": 1, "impactScore": 15, "keywords": null, "categoryId": null, "crmCustomers": ["Cleveland Clinic (Cleveland Clinic Foundation)"]}, {"id": "f8173abf-ddef-ef11-be20-6045bddbf891", "featureId": "MFR-M365-33576", "name": "M365 | Simulation mode for DLP for M365 Copilot", "description": "", "status": 172430007, "priority": 172430000, "created": "2025-02-20T22:55:15Z", "modified": "2026-03-26T15:17:44Z", "customers": 4, "impactScore": 62, "keywords": null, "categoryId": null, "crmCustomers": ["KLOUDYNET TECHNOLOGIES", "KPMG", "Accenture", "ETISALAT", "BP (British Petroleum, BP Oil International Ltd, BP Plc)"]}, {"id": "f75013ef-6fdc-ef11-8eea-7c1e525c63e3", "featureId": "MFR-M365-33250", "name": "Please Ignore Test feature Jan 2025 Sprint 2", "description": "Testing Add a new product to the M365 Engineering Assistance PortalMFR-M365-33250MFR-M365-33250MFR-M365-33250MFR-M365-33250 HomeSecurity CxE for Digital SellersCreate Digital Sellers Engineering Help RequestCreate Digital Sellers Engineering Help Request Targeted Customer Team works with Corporate and Major Growth customers to gather feedback, accelerate customer acquisition, and drive early adoption of our security solutions.Please provide as much information as possible so we can determine how to best assist you. In some cases, we may recommend other groups to support you.In-Scope RequestsPr...", "status": 172430000, "priority": 172430000, "created": "2025-01-27T05:31:22Z", "modified": "2025-04-21T07:08:13Z", "customers": 0, "impactScore": 0, "keywords": null, "categoryId": "c13733b3-6bdc-ef11-8ee9-000d3a10804e", "crmCustomers": []}, {"id": "618ac0b2-6edc-ef11-8eea-7c1e525c63e3", "featureId": "MFR-M365-33249", "name": "Please Ignore Test Record 01", "description": "For testing the User story Add a new product to the M365 Engineering Assistance Portal", "status": 172430000, "priority": 172430000, "created": "2025-01-27T05:22:34Z", "modified": "2025-01-27T05:26:54Z", "customers": 0, "impactScore": 0, "keywords": null, "categoryId": "c13733b3-6bdc-ef11-8ee9-000d3a10804e", "crmCustomers": ["TEST Customer"]}, {"id": "09427cd5-6bdc-ef11-8ee9-000d3a10804e", "featureId": "MFR-M365-33248", "name": "Test Purview for AI", "description": "", "status": 172430000, "priority": 172430000, "created": "2025-01-27T05:02:04Z", "modified": "2025-01-27T05:38:15Z", "customers": 0, "impactScore": null, "keywords": null, "categoryId": null, "crmCustomers": []}, {"id": "e16b27da-c55f-4278-b995-62bfe104add1", "featureId": "MFR-M365-30407", "name": "M365 | DLP for copilot interactions based on SITs", "description": "Ability to prevents user to submit Copilot prompts in Microsoft 365 Apps if: - The prompt contain specific / sensitive info- The request is related to specific / sensitive info contained in the document. eg : - prompt : create a text for <Sensitive info>- summarize <Doc with sensitive info> Goals are to prevent potential end-user abuse of the service and sensitive \"data in use\" to be processed in Copilot framework", "status": 172430007, "priority": 172430000, "created": "2024-04-04T18:10:21Z", "modified": "2026-03-26T15:16:58Z", "customers": 25, "impactScore": 407, "keywords": null, "categoryId": null, "crmCustomers": ["Accenture", "Ernst & Young (EY, E&Y, EY GLOBAL SERVICES LIMITED )", "ALLEN & OVERY", "TOTALENERGIES", "THE VANGUARD GROUP INC.", "CITIZENS FINANCIAL GROUP", "Cleveland Clinic (Cleveland Clinic Foundation)", "Corning Inc.", "Microsoft", "AVIVA GROUP HOLDINGS LIMITED (Aviva)", "BNY Mellon (Bank of New York Mellon)", "KPMG", "Wells Fargo (WELLS FARGO & COMPANY)", "Blackrock (BLACKROCK FINANCIAL MANAGEMENT)", "BIOGEN", "CONSULCESI", "Tchibo GmbH", "EDEKA", "Deutsche Telekom AG Konzernzentrale (DTAG / T-Systems)", "Increment Pty Ltd", "DEFEND LIMITED", "DZ PRIVATBANK S A", "JP Morgan Chase (JPMC)", "CIBC (Canadian Imperial Bank of Commerce)", "AmTrust North America", "ADP, LLC (Automatic Data Processing, Inc.)", "CONSTELLATION HOMEBUILDER SYSTEMS", "STATE STREET CORPORATION"]}, {"id": "2a036551-0945-4835-9747-eee0436abd3c", "featureId": "MFR-M365-29303", "name": "M365 | When Teams DLP blocks a message, P4AI should not provide a response to that message", "description": "When Teams DLP blocks a message because it contains sensitive data, users can still probe the data by asking Copilot, e.g. \"is there an SSN ending in 7180 in that last message?\" or \"did the diagnostic mentioned in the last message include Covid?\".  It's important to highlight that this is not about blocking the conversation with Copilot with DLP (different feature) since the prompt and response might not themselves have PII, but about ensuring that what was enforced for DLP doesn't have a loophole through Copilot prompting.", "status": 172430000, "priority": 172430000, "created": "2024-02-22T20:05:58Z", "modified": "2026-03-26T15:18:55Z", "customers": 1, "impactScore": 15, "keywords": null, "categoryId": null, "crmCustomers": ["TOTALENERGIES", "ALLEN & OVERY", "AMEREN UE"]}, {"id": "038a5d0b-8685-4b95-b637-2d6742dd26ad", "featureId": "MFR-M365-28721", "name": "M365 | DLM: Distinguish Copilot session title and prompt history to avoid confusion", "description": "Scenario: Customers misunderstand that the Copilot user prompts are not being deleted along with the chat history by retention policies. This is due to the fact that by default the session title is based on the initial prompt submitted by the user (up to a certain character limit) and so it appears that it is in fact the user prompt. This causes customers to believe the prompt history is being retained beyond the applicable policy timing. Currently, copilot interactions are saved like Teams messages, and Teams messages are stored like emails with a body and a subject line. Because there are no...", "status": 172430000, "priority": 172430000, "created": "2024-01-09T18:05:55Z", "modified": "2026-03-26T13:25:37Z", "customers": 2, "impactScore": 48, "keywords": "Copilot", "categoryId": null, "crmCustomers": ["Pricewaterhouse Coopers (PWC, PricewaterhouseCoopers LLP)", "Premera Blue Cross"]}];